import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ClassicalPiece {
  id: string;
  date: string;
  composer: string;
  title: string;
  year: string;
  era: string;
  description: string;
  mood: string;
  funFact: string;
  youtubeQuery: string;
  imageUrl: string;
}

export enum ViewState {
  HOME = 'HOME',
  HISTORY = 'HISTORY',
  SUBSCRIBE = 'SUBSCRIBE'
}

import { GoogleGenAI, Type } from "@google/genai";
import { ClassicalPiece } from "../types";

const API_KEY = process.env.API_KEY || "";

export const generateDailyPiece = async (date: string): Promise<ClassicalPiece> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Recommend a specific classical music masterpiece for the date: ${date}. 
               Include details about the composer, the work, its era, a short poetic description, 
               the mood it evokes, and one interesting fun fact. 
               Also provide a highly specific YouTube search query for a world-class performance.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          composer: { type: Type.STRING },
          title: { type: Type.STRING },
          year: { type: Type.STRING },
          era: { type: Type.STRING },
          description: { type: Type.STRING },
          mood: { type: Type.STRING },
          funFact: { type: Type.STRING },
          youtubeQuery: { type: Type.STRING },
        },
        required: ["composer", "title", "year", "era", "description", "mood", "funFact", "youtubeQuery"]
      }
    }
  });

  const data = JSON.parse(response.text);

  // Enhance with a placeholder image based on composer or era
  const imageUrl = `https://picsum.photos/seed/${encodeURIComponent(data.composer)}/1200/800`;

  return {
    id: btoa(date + data.title),
    date,
    ...data,
    imageUrl
  };
};

import React, { useState, useEffect, useCallback } from 'react';
import { Navbar } from './components/Navbar';
import { RecommendationCard } from './components/RecommendationCard';
import { HistoryList } from './components/HistoryList';
import { SubscriptionForm } from './components/SubscriptionForm';
import { generateDailyPiece } from './services/geminiService';
import { ClassicalPiece, ViewState } from './types';
import { Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.HOME);
  const [todayPiece, setTodayPiece] = useState<ClassicalPiece | null>(null);
  const [history, setHistory] = useState<ClassicalPiece[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const fetchTodayRecommendation = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const today = new Date().toISOString().split('T')[0];

      // Try to load from local storage first
      const saved = localStorage.getItem(`classic_daily_${today}`);
      if (saved) {
        setTodayPiece(JSON.parse(saved));
      } else {
        const piece = await generateDailyPiece(today);
        setTodayPiece(piece);
        localStorage.setItem(`classic_daily_${today}`, JSON.stringify(piece));

        // Add to history
        const existingHistoryRaw = localStorage.getItem('classic_history');
        const existingHistory = existingHistoryRaw ? JSON.parse(existingHistoryRaw) : [];
        const updatedHistory = [piece, ...existingHistory.filter((p: any) => p.date !== today)].slice(0, 10);
        localStorage.setItem('classic_history', JSON.stringify(updatedHistory));
        setHistory(updatedHistory);
      }
    } catch (err) {
      console.error(err);
      setError("Failed to compose today's recommendation. Please try again later.");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchTodayRecommendation();
    const savedHistory = localStorage.getItem('classic_history');
    if (savedHistory) {
      setHistory(JSON.parse(savedHistory));
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const renderContent = () => {
    if (loading) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-4">
          <Loader2 className="w-12 h-12 text-amber-700 animate-spin" />
          <p className="text-xl serif italic text-amber-900">Curating today's masterpiece...</p>
        </div>
      );
    }

    if (error) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6">
          <p className="text-red-600 mb-4">{error}</p>
          <button 
            onClick={fetchTodayRecommendation}
            className="px-6 py-2 bg-amber-800 text-white rounded-full hover:bg-amber-900 transition"
          >
            Retry
          </button>
        </div>
      );
    }

    switch (currentView) {
      case ViewState.HOME:
        return todayPiece && <RecommendationCard piece={todayPiece} />;
      case ViewState.HISTORY:
        return <HistoryList items={history} onSelect={(p) => { setTodayPiece(p); setCurrentView(ViewState.HOME); }} />;
      case ViewState.SUBSCRIBE:
        return <SubscriptionForm />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar activeView={currentView} setView={setCurrentView} />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-5xl">
        <div className="mb-12 text-center">
          <h1 className="text-5xl md:text-6xl font-bold text-amber-950 mb-2">ClassicDaily</h1>
          <p className="text-amber-800 italic text-lg serif">A Moment of Timeless Elegance, Delivered Daily.</p>
        </div>

        {renderContent()}
      </main>

      <footer className="bg-amber-950 text-amber-100/60 py-8 px-4 text-center border-t border-amber-900/20">
        <p className="text-sm">© 2024 ClassicDaily. Curated by Gemini AI.</p>
        <p className="text-xs mt-2 uppercase tracking-widest">Symphony • Sonata • Concerto • Opera</p>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { ViewState } from '../types';
import { Music, Calendar, Mail } from 'lucide-react';

interface NavbarProps {
