import React, { useState } from 'react';
import { ClassicalPiece } from '../types';
import { Share2, Youtube, Quote, Info, Check, Copy } from 'lucide-react';

interface RecommendationCardProps {
  piece: ClassicalPiece;
}

export const RecommendationCard: React.FC<RecommendationCardProps> = ({ piece }) => {
  const [copied, setCopied] = useState(false);

  const handleShare = async () => {
    const shareText = `[ClassicDaily] Today's Masterpiece: ${piece.composer} - ${piece.title}\n\n"${piece.description}"\n\nListen here: https://www.youtube.com/results?search_query=${encodeURIComponent(piece.youtubeQuery)}`;

    if (navigator.share) {
      try {
        await navigator.share({
          title: 'ClassicDaily Recommendation',
          text: shareText,
          url: window.location.href,
        });
      } catch (err) {
        console.log('Error sharing', err);
      }
    } else {
      // Fallback: Copy to clipboard
      navigator.clipboard.writeText(shareText);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const handleKakaoShare = () => {
    // In a real app with Kakao SDK:
    // Kakao.Link.sendDefault({ ... })
    // For this demo, we use the Web Share API which triggers KakaoTalk if installed on mobile
    handleShare();
  };

  return (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-1000">
      <div className="bg-white rounded-2xl overflow-hidden shadow-xl border border-amber-50 relative">
        <div className="h-64 md:h-96 relative">
          <img 
            src={piece.imageUrl} 
            alt={piece.composer} 
            className="w-full h-full object-cover grayscale-[20%] sepia-[10%] hover:scale-105 transition duration-700"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent flex flex-col justify-end p-6 md:p-10">
            <span className="text-amber-400 font-medium uppercase tracking-widest text-sm mb-2">{piece.era} • {piece.year}</span>
            <h2 className="text-3xl md:text-5xl text-white font-bold leading-tight">{piece.title}</h2>
            <p className="text-xl md:text-2xl text-amber-100/90 serif italic mt-1">{piece.composer}</p>
          </div>
        </div>

        <div className="p-6 md:p-10 grid grid-cols-1 lg:grid-cols-3 gap-10">
          <div className="lg:col-span-2 space-y-8">
            <section>
              <div className="flex items-center space-x-2 text-amber-900 mb-4">
                <Quote className="w-5 h-5 fill-amber-900" />
                <h3 className="text-xl font-bold uppercase tracking-tighter">About the Work</h3>
              </div>
              <p className="text-lg text-amber-950/80 leading-relaxed font-light">
                {piece.description}
              </p>
            </section>

            <section className="bg-amber-50/50 p-6 rounded-xl border border-amber-100/50">
              <div className="flex items-center space-x-2 text-amber-900 mb-3">
                <Info className="w-5 h-5" />
                <h3 className="text-lg font-bold uppercase tracking-tighter">Did you know?</h3>
              </div>
              <p className="text-amber-900/80 italic">
                {piece.funFact}
              </p>
            </section>

            <div className="flex flex-wrap gap-4">
              <a 
                href={`https://www.youtube.com/results?search_query=${encodeURIComponent(piece.youtubeQuery)}`}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center space-x-2 px-6 py-3 bg-red-600 hover:bg-red-700 text-white rounded-full transition shadow-md hover:shadow-lg"
              >
                <Youtube className="w-5 h-5" />
                <span className="font-semibold">Listen on YouTube</span>
              </a>

              <button 
                onClick={handleKakaoShare}
                className="flex items-center space-x-2 px-6 py-3 bg-[#FEE500] hover:bg-[#FADC00] text-[#191919] rounded-full transition shadow-md hover:shadow-lg"
              >
                <Share2 className="w-5 h-5" />
                <span className="font-semibold">Share via Kakao</span>
              </button>

              <button 
                onClick={handleShare}
                className="flex items-center space-x-2 px-4 py-3 bg-amber-100 hover:bg-amber-200 text-amber-900 rounded-full transition"
              >
                {copied ? <Check className="w-5 h-5 text-green-600" /> : <Copy className="w-5 h-5" />}
                <span className="font-medium">{copied ? 'Copied!' : 'Copy Link'}</span>
              </button>
            </div>
          </div>

          <div className="space-y-6">
             <div className="bg-white border border-amber-100 p-6 rounded-2xl shadow-sm">
                <h4 className="text-sm font-bold text-amber-900 uppercase tracking-widest mb-4">Atmosphere</h4>
                <div className="flex flex-wrap gap-2">
                  {piece.mood.split(',').map((m, i) => (
                    <span key={i} className="px-3 py-1 bg-amber-50 text-amber-800 text-xs rounded-full border border-amber-100 font-medium">
                      {m.trim()}
                    </span>
                  ))}
                </div>
             </div>

             <div className="bg-amber-900 text-amber-100 p-6 rounded-2xl shadow-sm">
                <h4 className="text-sm font-bold uppercase tracking-widest mb-4 text-amber-400">Daily Digest</h4>
                <p className="text-sm leading-relaxed text-amber-100/80">
                  Receive this recommendation every morning at 8:00 AM. Join 5,000+ classical music lovers.
                </p>
                <button className="mt-4 w-full py-2 bg-amber-400 text-amber-950 font-bold rounded-lg hover:bg-amber-300 transition text-sm">
                  Enable Notifications
                </button>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

