import React, { useState } from 'react';
import { Mail, CheckCircle2, Sparkles, Send } from 'lucide-react';

export const SubscriptionForm: React.FC = () => {
  const [email, setEmail] = useState('');
  const [submitted, setSubmitted] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    // Simulate API call
    setTimeout(() => {
      setLoading(false);
      setSubmitted(true);
    }, 1500);
  };

  if (submitted) {
    return (
      <div className="max-w-xl mx-auto text-center py-20 animate-in zoom-in duration-500">
        <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6">
          <CheckCircle2 className="w-10 h-10 text-green-600" />
        </div>
        <h3 className="text-3xl font-serif text-amber-950 mb-4">Welcome to the Ensemble!</h3>
        <p className="text-amber-800 leading-relaxed mb-8">
          A confirmation symphony has been sent to <strong>{email}</strong>.<br />
          Prepare your ears for a daily journey through the classics.
        </p>
        <button 
          onClick={() => setSubmitted(false)}
          className="text-amber-700 underline font-medium hover:text-amber-900"
        >
          Subscribe another email
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto bg-amber-950 rounded-[2rem] overflow-hidden shadow-2xl flex flex-col md:flex-row animate-in fade-in slide-in-from-bottom-8 duration-1000">
      <div className="md:w-1/2 p-10 md:p-16 flex flex-col justify-center text-amber-100 space-y-6">
        <div className="w-12 h-12 bg-amber-800/50 rounded-xl flex items-center justify-center mb-2">
          <Sparkles className="w-6 h-6 text-amber-400" />
        </div>
        <h2 className="text-4xl font-serif leading-tight">The Morning<br />Symphony</h2>
        <p className="text-amber-100/70 text-lg leading-relaxed">
          Join our curated newsletter and start every morning with one hand-picked masterpiece, historical context, and premium performance links.
        </p>
        <ul className="space-y-3 text-sm text-amber-100/60">
          <li className="flex items-center"><CheckCircle2 className="w-4 h-4 mr-2 text-amber-400" /> No ads, just art</li>
          <li className="flex items-center"><CheckCircle2 className="w-4 h-4 mr-2 text-amber-400" /> Weekly composer spotlights</li>
          <li className="flex items-center"><CheckCircle2 className="w-4 h-4 mr-2 text-amber-400" /> Links to Hi-Fi recordings</li>
        </ul>
      </div>

      <div className="md:w-1/2 bg-amber-900/40 p-10 md:p-16 flex flex-col justify-center">
        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <label htmlFor="email" className="block text-amber-200 text-sm font-semibold uppercase tracking-widest">Email Address</label>
            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-amber-500" />
              <input
                id="email"
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="vivaldi@orchestra.com"
                className="w-full pl-12 pr-4 py-4 bg-amber-950/50 border border-amber-800 rounded-xl text-amber-100 placeholder:text-amber-700 focus:outline-none focus:ring-2 focus:ring-amber-500 transition"
              />
            </div>
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full py-4 bg-amber-400 hover:bg-amber-300 disabled:bg-amber-800 disabled:cursor-not-allowed text-amber-950 font-bold rounded-xl transition shadow-lg flex items-center justify-center space-x-2"
          >
            {loading ? (
              <span className="animate-pulse">Tuning instruments...</span>
            ) : (
              <>
                <span>Join the Newsletter</span>
                <Send className="w-4 h-4" />
              </>
            )}
          </button>

          <p className="text-xs text-amber-100/40 text-center">
            You can unsubscribe anytime. We respect your peace.
          </p>
        </form>
      </div>
    </div>
  );
};

export interface ClassicalPiece {
  id: string;
  date: string;
  composer: string;
  title: string;
  year: string;
  era: string;
  description: string;
  mood: string;
  funFact: string;
  youtubeQuery: string;
  imageUrl: string;
  premiumNotes?: string; // Long-form program notes for paid users
}

export enum SubscriptionTier {
  FREE = 'FREE',
  PREMIUM = 'PREMIUM'
}

export enum ViewState {
  HOME = 'HOME',
  HISTORY = 'HISTORY',
  SUBSCRIBE = 'SUBSCRIBE',
  PRICING = 'PRICING'
}

import React, { useState, useEffect, useCallback } from 'react';
import { Navbar } from './components/Navbar';
import { RecommendationCard } from './components/RecommendationCard';
import { HistoryList } from './components/HistoryList';
import { SubscriptionForm } from './components/SubscriptionForm';
import { PricingSection } from './components/PricingSection';
import { generateDailyPiece } from './services/geminiService';
import { ClassicalPiece, ViewState, SubscriptionTier } from './types';
import { Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.HOME);
  const [tier, setTier] = useState<SubscriptionTier>(SubscriptionTier.FREE);
  const [todayPiece, setTodayPiece] = useState<ClassicalPiece | null>(null);
  const [history, setHistory] = useState<ClassicalPiece[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const fetchTodayRecommendation = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const today = new Date().toISOString().split('T')[0];
      const saved = localStorage.getItem(`classic_daily_${today}`);

      if (saved) {
        setTodayPiece(JSON.parse(saved));
      } else {
        const piece = await generateDailyPiece(today);
        setTodayPiece(piece);
        localStorage.setItem(`classic_daily_${today}`, JSON.stringify(piece));

        const existingHistoryRaw = localStorage.getItem('classic_history');
        const existingHistory = existingHistoryRaw ? JSON.parse(existingHistoryRaw) : [];
        const updatedHistory = [piece, ...existingHistory.filter((p: any) => p.date !== today)].slice(0, 10);
        localStorage.setItem('classic_history', JSON.stringify(updatedHistory));
        setHistory(updatedHistory);
      }
    } catch (err) {
      console.error(err);
      setError("Failed to compose today's recommendation. Please try again later.");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchTodayRecommendation();
    const savedHistory = localStorage.getItem('classic_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedTier = localStorage.getItem('user_tier') as SubscriptionTier;
    if (savedTier) setTier(savedTier);
  }, [fetchTodayRecommendation]);

  const handleUpgrade = () => {
    setTier(SubscriptionTier.PREMIUM);
    localStorage.setItem('user_tier', SubscriptionTier.PREMIUM);
    setCurrentView(ViewState.HOME);
  };

  const renderContent = () => {
    if (loading) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-4">
          <Loader2 className="w-12 h-12 text-amber-700 animate-spin" />
          <p className="text-xl serif italic text-amber-900">Curating today's masterpiece...</p>
        </div>
      );
    }

    if (error) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6">
          <p className="text-red-600 mb-4">{error}</p>
          <button onClick={fetchTodayRecommendation} className="px-6 py-2 bg-amber-800 text-white rounded-full">Retry</button>
        </div>
      );
    }

    switch (currentView) {
      case ViewState.HOME:
        return todayPiece && <RecommendationCard piece={todayPiece} tier={tier} onUpgrade={() => setCurrentView(ViewState.PRICING)} />;
      case ViewState.HISTORY:
        return <HistoryList items={history} tier={tier} onSelect={(p) => { setTodayPiece(p); setCurrentView(ViewState.HOME); }} onUpgrade={() => setCurrentView(ViewState.PRICING)} />;
      case ViewState.SUBSCRIBE:
        return <SubscriptionForm />;
      case ViewState.PRICING:
        return <PricingSection onSelectPlan={handleUpgrade} currentTier={tier} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar activeView={currentView} setView={setCurrentView} tier={tier} />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-5xl">
        <div className="mb-12 text-center">
          <h1 className="text-5xl md:text-6xl font-bold text-amber-950 mb-2">ClassicDaily</h1>
          <p className="text-amber-800 italic text-lg serif">Exclusive Masterpieces for Connoisseurs.</p>
        </div>

        {renderContent()}
      </main>

      <footer className="bg-amber-950 text-amber-100/60 py-12 px-4 text-center border-t border-amber-900/20">
        <div className="max-w-2xl mx-auto mb-8 grid grid-cols-2 md:grid-cols-4 gap-4 text-xs font-bold tracking-tighter uppercase opacity-50">
          <span>Daily Curation</span>
          <span>FLAC Quality</span>
          <span>Program Notes</span>
          <span>Expert Analysis</span>
        </div>
        <p className="text-sm">© 2024 ClassicDaily. Curated by Gemini AI.</p>
      </footer>
    </div>
  );
};

