import { GoogleGenAI, Type } from "@google/genai";
import { ClassicalPiece } from "../types";

export const generateDailyPiece = async (date: string): Promise<ClassicalPiece> => {
  // Always obtain the API key exclusively from process.env.API_KEY and use a named parameter for initialization
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Recommend a specific classical music masterpiece for the date: ${date}. 
               Include details about the composer, the work, its era, a short poetic description, 
               the mood it evokes, and one interesting fun fact. 
               Also provide a highly specific YouTube search query for a world-class performance.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          composer: { type: Type.STRING },
          title: { type: Type.STRING },
          year: { type: Type.STRING },
          era: { type: Type.STRING },
          description: { type: Type.STRING },
          mood: { type: Type.STRING },
          funFact: { type: Type.STRING },
          youtubeQuery: { type: Type.STRING },
        },
        required: ["composer", "title", "year", "era", "description", "mood", "funFact", "youtubeQuery"]
      }
    }
  });

  // Extract the generated text using the .text property as per SDK documentation
  const jsonStr = (response.text || "").trim();
  const data = JSON.parse(jsonStr);

  // Enhance with a placeholder image based on composer or era
  const imageUrl = `https://picsum.photos/seed/${encodeURIComponent(data.composer)}/1200/800`;

  return {
    id: btoa(date + data.title),
    date,
    ...data,
    imageUrl
  };
};

