import React, { useState, useEffect, useCallback } from 'react';
import { Navbar } from './components/Navbar';
import { RecommendationCard } from './components/RecommendationCard';
import { HistoryList } from './components/HistoryList';
import { SubscriptionForm } from './components/SubscriptionForm';
import { PricingSection } from './components/PricingSection';
import { AdminPanel } from './components/AdminPanel';
import { generateDailyPiece } from './services/geminiService';
import { ClassicalPiece, ViewState, SubscriptionTier } from './types';
import { Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.HOME);
  const [tier, setTier] = useState<SubscriptionTier>(SubscriptionTier.FREE);
  const [todayPiece, setTodayPiece] = useState<ClassicalPiece | null>(null);
  const [history, setHistory] = useState<ClassicalPiece[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const fetchTodayRecommendation = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const today = new Date().toISOString().split('T')[0];
      const saved = localStorage.getItem(`classic_daily_${today}`);

      if (saved) {
        setTodayPiece(JSON.parse(saved));
      } else {
        const piece = await generateDailyPiece(today);
        setTodayPiece(piece);
        localStorage.setItem(`classic_daily_${today}`, JSON.stringify(piece));

        const existingHistoryRaw = localStorage.getItem('classic_history');
        const existingHistory = existingHistoryRaw ? JSON.parse(existingHistoryRaw) : [];
        const updatedHistory = [piece, ...existingHistory.filter((p: any) => p.date !== today)].slice(0, 10);
        localStorage.setItem('classic_history', JSON.stringify(updatedHistory));
        setHistory(updatedHistory);
      }
    } catch (err) {
      console.error(err);
      setError("오늘의 추천곡을 구성하지 못했습니다. 다시 시도해주세요.");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchTodayRecommendation();
    const savedHistory = localStorage.getItem('classic_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedTier = localStorage.getItem('user_tier') as SubscriptionTier;
    if (savedTier) setTier(savedTier);
  }, [fetchTodayRecommendation]);

  const handleUpgrade = () => {
    setTier(SubscriptionTier.PREMIUM);
    localStorage.setItem('user_tier', SubscriptionTier.PREMIUM);
    setCurrentView(ViewState.HOME);
  };

  const renderContent = () => {
    if (loading) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-4">
          <Loader2 className="w-12 h-12 text-amber-700 animate-spin" />
          <p className="text-xl serif italic text-amber-900">오늘의 명작을 큐레이팅 중입니다...</p>
        </div>
      );
    }

    if (error) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6">
          <p className="text-red-600 mb-4">{error}</p>
          <button onClick={fetchTodayRecommendation} className="px-6 py-2 bg-amber-800 text-white rounded-full">다시 시도</button>
        </div>
      );
    }

    switch (currentView) {
      case ViewState.HOME:
        return todayPiece && <RecommendationCard piece={todayPiece} tier={tier} onUpgrade={() => setCurrentView(ViewState.PRICING)} />;
      case ViewState.HISTORY:
        return <HistoryList items={history} tier={tier} onSelect={(p) => { setTodayPiece(p); setCurrentView(ViewState.HOME); }} onUpgrade={() => setCurrentView(ViewState.PRICING)} />;
      case ViewState.SUBSCRIBE:
        return <SubscriptionForm />;
      case ViewState.PRICING:
        return <PricingSection onSelectPlan={handleUpgrade} currentTier={tier} />;
      case ViewState.ADMIN:
        return <AdminPanel todayPiece={todayPiece} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar activeView={currentView} setView={setCurrentView} tier={tier} />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-5xl">
        <div className="mb-12 text-center">
          <h1 className="text-5xl md:text-6xl font-bold text-amber-950 mb-2">ClassicDaily</h1>
          <p className="text-amber-800 italic text-lg serif">고품격 클래식 명곡, 매일 아침 배달됩니다.</p>
        </div>

        {renderContent()}
      </main>

      <footer className="bg-amber-950 text-amber-100/60 py-12 px-4 text-center border-t border-amber-900/20">
        <div className="max-w-2xl mx-auto mb-8 grid grid-cols-2 md:grid-cols-4 gap-4 text-xs font-bold tracking-tighter uppercase opacity-50">
          <span>Daily Curation</span>
          <span>FLAC Quality</span>
          <span>Program Notes</span>
          <span>Expert Analysis</span>
        </div>
        <p className="text-sm">© 2024 ClassicDaily. Curated by Gemini AI.</p>
      </footer>
    </div>
  );
};

