import React, { useState, useEffect, useCallback } from 'react';
import { Navbar } from './components/Navbar';
import { RecommendationCard } from './components/RecommendationCard';
import { HistoryList } from './components/HistoryList';
import { SubscriptionForm } from './components/SubscriptionForm';
import { PricingSection } from './components/PricingSection';
import { AdminPanel } from './components/AdminPanel';
import { CuratorWorkplace } from './components/CuratorWorkplace';
import { generateCandidates } from './services/geminiService';
import { ClassicalPiece, ViewState, SubscriptionTier } from './types';
import { Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.CURATE);
  const [tier, setTier] = useState<SubscriptionTier>(SubscriptionTier.FREE);
  const [todayPiece, setTodayPiece] = useState<ClassicalPiece | null>(null);
  const [candidates, setCandidates] = useState<ClassicalPiece[]>([]);
  const [history, setHistory] = useState<ClassicalPiece[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [isSearching, setIsSearching] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const fetchCurationData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const today = new Date().toISOString().split('T')[0];
      const savedPiece = localStorage.getItem(`classic_daily_${today}`);

      if (savedPiece) {
        setTodayPiece(JSON.parse(savedPiece));
        setCurrentView(ViewState.HOME);
      } else {
        const results = await generateCandidates(today);
        setCandidates(results);
        setCurrentView(ViewState.CURATE);
      }
    } catch (err) {
      console.error(err);
      setError("큐레이션 후보를 불러오지 못했습니다. 잠시 후 다시 시도해주세요.");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchCurationData();
    const savedHistory = localStorage.getItem('classic_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, [fetchCurationData]);

  const handleCustomSearch = async (composer: string, mood: string) => {
    setIsSearching(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const results = await generateCandidates(today, { composer, mood });
      setCandidates(results);
    } catch (err) {
      console.error(err);
      alert("검색에 실패했습니다. 다른 키워드를 입력해보세요.");
    } finally {
      setIsSearching(false);
    }
  };

  const handleConfirmPiece = (piece: ClassicalPiece) => {
    const today = new Date().toISOString().split('T')[0];
    setTodayPiece(piece);
    localStorage.setItem(`classic_daily_${today}`, JSON.stringify(piece));

    const existingHistoryRaw = localStorage.getItem('classic_history');
    const existingHistory = existingHistoryRaw ? JSON.parse(existingHistoryRaw) : [];
    const updatedHistory = [piece, ...existingHistory.filter((p: any) => p.id !== piece.id)].slice(0, 10);
    localStorage.setItem('classic_history', JSON.stringify(updatedHistory));
    setHistory(updatedHistory);

    setCurrentView(ViewState.HOME);
  };

  const renderContent = () => {
    if (loading) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-4 text-center">
          <Loader2 className="w-12 h-12 text-amber-700 animate-spin" />
          <p className="text-xl serif italic text-amber-900 leading-relaxed">
            큐레이터님을 위한 오늘의 후보곡들을<br />Gemini AI가 엄선하고 있습니다...
          </p>
        </div>
      );
    }

    if (error) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6">
          <p className="text-red-600 mb-4">{error}</p>
          <button onClick={fetchCurationData} className="px-6 py-2 bg-amber-800 text-white rounded-full font-bold">후보곡 다시 부르기</button>
        </div>
      );
    }

    switch (currentView) {
      case ViewState.CURATE:
        return (
          <CuratorWorkplace 
            candidates={candidates} 
            onConfirm={handleConfirmPiece} 
            onSearch={handleCustomSearch}
            isSearching={isSearching}
          />
        );
      case ViewState.HOME:
        return todayPiece && <RecommendationCard piece={todayPiece} tier={SubscriptionTier.PREMIUM} onUpgrade={() => {}} />;
      case ViewState.HISTORY:
        return <HistoryList items={history} tier={SubscriptionTier.PREMIUM} onSelect={(p) => { setTodayPiece(p); setCurrentView(ViewState.HOME); }} onUpgrade={() => {}} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#fcfaf7]">
      <Navbar activeView={currentView} setView={setCurrentView} tier={SubscriptionTier.PREMIUM} />

      <main className="flex-grow container mx-auto px-4 py-12 max-w-5xl">
        <div className="mb-16 text-center">
          <div className="inline-block px-4 py-1 bg-amber-100 text-amber-800 text-xs font-black uppercase tracking-widest rounded-full mb-4">
            Curator's Studio
          </div>
          <h1 className="text-5xl md:text-7xl font-bold text-amber-950 mb-4 tracking-tight">ClassicDaily</h1>
          <p className="text-amber-800 italic text-xl serif">당신의 감각으로 완성하는 오늘의 명작.</p>
        </div>

        {renderContent()}
      </main>

      <footer className="bg-amber-950 text-amber-100/30 py-16 px-4 text-center border-t border-amber-900/20">
        <p className="text-sm font-serif italic mb-2">"Music is the shorthand of emotion." — Leo Tolstoy</p>
        <p className="text-xs uppercase tracking-widest font-bold opacity-50">© 2024 ClassicDaily • Curator Edition</p>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { ClassicalPiece } from "../types";

export interface CurationFilters {
  composer?: string;
  mood?: string;
  discoveryMode?: 'popular' | 'balanced' | 'obscure';
  era?: string;
}

export const generateCandidates = async (date: string, filters?: CurationFilters): Promise<ClassicalPiece[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const modeInstruction = {
    popular: "대중적으로 널리 알려진 친숙한 명곡 위주로 선정해주세요.",
    balanced: "유명한 곡과 음악사적으로 의미 있는 곡을 적절히 섞어주세요.",
    obscure: "음악 애호가들 사이에서만 알려진, 예술성이 뛰어나지만 대중적으로는 드문 '숨겨진 보석' 같은 곡들을 발굴해주세요."
  }[filters?.discoveryMode || 'balanced'];

  let filterInstructions = "";
  if (filters?.composer) filterInstructions += `작곡가는 반드시 '${filters.composer}'와(과) 관련되어야 합니다. `;
  if (filters?.mood) filterInstructions += `전체적인 분위기는 '${filters.mood}' 느낌이 나도록 선정해주세요. `;
  if (filters?.era) filterInstructions += `음악적 시대는 '${filters.era}' 시대로 한정해주세요. `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `오늘은 ${date}입니다. 오늘 배포할 클래식 음악 뉴스레터를 위해 서로 다른 분위기의 후보곡 3개를 추천해주세요.

               [필수 지침]
               1. ${modeInstruction}
               2. ${filterInstructions}
               3. 동일한 곡을 반복 추천하지 않도록 노력하고, 각 곡의 역사적 맥락과 큐레이션 포인트를 상세히 기술해주세요.
               4. 작곡가, 곡 제목, 작곡 연도, 시대, 설명(한글), 분위기, 흥미로운 사실, 유튜브 검색어를 포함해야 합니다.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            composer: { type: Type.STRING },
            title: { type: Type.STRING },
            year: { type: Type.STRING },
            era: { type: Type.STRING },
            description: { type: Type.STRING },
            mood: { type: Type.STRING },
            funFact: { type: Type.STRING },
            youtubeQuery: { type: Type.STRING },
          },
          required: ["composer", "title", "year", "era", "description", "mood", "funFact", "youtubeQuery"]
        }
      }
    }
  });

  const jsonStr = (response.text || "").trim();
  const candidates: any[] = JSON.parse(jsonStr);

  return candidates.map((data, index) => ({
    id: btoa(date + data.title + index + (filters?.composer || "")),
    date,
    ...data,
    imageUrl: `https://picsum.photos/seed/${encodeURIComponent(data.composer + index + (filters?.discoveryMode || ""))}/800/600`
  }));
};

