  };

  return (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-1000">
      <div className={`bg-white rounded-3xl overflow-hidden shadow-2xl border relative ${isPremium ? 'ring-2 ring-amber-400/30' : 'border-amber-50'}`}>
        {isPremium && (
          <div className="absolute top-4 right-4 z-10 bg-amber-500 text-white px-3 py-1 rounded-full text-xs font-black uppercase flex items-center shadow-lg">
            <Sparkles className="w-3 h-3 mr-1" /> Premium Content
          </div>
