import { GoogleGenAI, Type } from "@google/genai";
import { ClassicalPiece } from "../types";

export interface CurationFilters {
  composer?: string;
  mood?: string;
  performer?: string;
  discoveryMode?: 'popular' | 'balanced' | 'obscure';
  era?: string;
}

export const generateCandidates = async (date: string, filters?: CurationFilters): Promise<ClassicalPiece[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const modeInstruction = {
    popular: "대중적으로 널리 알려진 친숙한 명곡 위주로 선정해주세요.",
    balanced: "유명한 곡과 음악사적으로 의미 있는 곡을 적절히 섞어주세요.",
    obscure: "음악 애호가들 사이에서만 알려진 숨겨진 보석 같은 곡들을 발굴해주세요."
  }[filters?.discoveryMode || 'balanced'];

  // 검색 필터가 있을 경우 AI에게 매우 엄격한 지시를 내립니다.
  let strictFilterInstructions = "";
  if (filters?.composer) {
    strictFilterInstructions += `\n[CRITICAL CONSTRAINT] 모든 후보곡의 작곡가는 반드시 '${filters.composer}'여야 합니다. 예외는 없습니다.`;
  }
  if (filters?.performer) {
    strictFilterInstructions += `\n[CRITICAL CONSTRAINT] 모든 후보곡은 반드시 '${filters.performer}'의 연주(또는 지휘/협연) 버전이어야 합니다. 'performer' 필드값은 반드시 '${filters.performer}'를 포함해야 하며, 유튜브 검색어(youtubeQuery)에도 반드시 이 이름이 포함되어야 합니다.`;
  }
  if (filters?.era) {
    strictFilterInstructions += `\n[ERA CONSTRAINT] 곡의 시대 배경은 반드시 '${filters.era}'여야 합니다.`;
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `오늘은 ${date}입니다. 오늘 배포할 클래식 음악 뉴스레터를 위해 후보곡 3개를 추천해주세요.

               [기본 가이드라인]
               1. ${modeInstruction}
               2. 분위기(Mood): ${filters?.mood || "서로 다른 다채로운 분위기"}
               ${strictFilterInstructions}

               [데이터 품질 요구사항]
               - 입력된 검색어(작곡가, 연주자)가 있다면, 3개의 후보 모두 해당 조건을 '100% 충족'해야 합니다. 
               - 만약 특정 연주자가 해당 작곡가의 곡을 연주한 적이 없다면, 그 연주자의 다른 유명한 레퍼토리를 추천하되 반드시 해당 연주자의 이름이 유지되어야 합니다.
               - 유튜브 검색어(youtubeQuery)는 [작곡가 + 곡 제목 + 연주자 이름] 형식으로 생성하여 사용자가 바로 최적의 연주를 찾을 수 있게 하세요.

               각 곡의 상세 설명은 한국어로 작성하며, 큐레이터가 뉴스레터에 바로 사용할 수 있도록 우아한 문체를 유지하세요.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            composer: { type: Type.STRING },
            title: { type: Type.STRING },
            year: { type: Type.STRING },
            era: { type: Type.STRING },
            performer: { type: Type.STRING, description: "입력된 연주자 필터와 일치하는 연주자 이름" },
            description: { type: Type.STRING },
            mood: { type: Type.STRING },
            funFact: { type: Type.STRING },
            youtubeQuery: { type: Type.STRING },
          },
          required: ["composer", "title", "year", "era", "performer", "description", "mood", "funFact", "youtubeQuery"]
        }
      }
    }
  });

  const jsonStr = (response.text || "").trim();
  const candidates: any[] = JSON.parse(jsonStr);

  return candidates.map((data, index) => ({
    id: btoa(date + data.title + index + (filters?.composer || "") + (filters?.performer || "")),
    date,
    ...data,
    imageUrl: `https://picsum.photos/seed/${encodeURIComponent(data.composer + index + (filters?.performer || "classic"))}/800/600`
  }));
};

