import { GoogleGenAI, Type } from "@google/genai";
import { ClassicalPiece } from "../types";

export interface CurationFilters {
  composer?: string;
  mood?: string;
  performer?: string;
  discoveryMode?: 'popular' | 'balanced' | 'obscure';
  era?: string;
}

export interface CurationInspiration {
  theme: string;
  reason: string;
  filters: CurationFilters;
}

// AI에게 오늘의 큐레이션 테마 아이디어를 3개 요청합니다.
export const getInspirations = async (date: string): Promise<CurationInspiration[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `오늘은 ${date}입니다. 클래식 음악 큐레이터를 위해 오늘 시도해볼만한 매력적인 큐레이션 테마 3가지를 제안해주세요. 
               각 테마는 대중적인 것, 전문적인 것, 그리고 한국 연주자와 관련된 것을 적절히 섞어주세요.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            theme: { type: Type.STRING, description: "테마의 매력적인 제목 (예: 새벽을 여는 바흐의 무곡)" },
            reason: { type: Type.STRING, description: "이 테마를 추천하는 짧은 이유" },
            filters: {
              type: Type.OBJECT,
              properties: {
                composer: { type: Type.STRING },
                performer: { type: Type.STRING },
                mood: { type: Type.STRING },
                era: { type: Type.STRING },
                discoveryMode: { type: Type.STRING }
              }
            }
          },
          required: ["theme", "reason", "filters"]
        }
      }
    }
  });

  return JSON.parse(response.text || "[]");
};

export const generateCandidates = async (date: string, filters?: CurationFilters): Promise<ClassicalPiece[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const modeInstruction = {
    popular: "대중적으로 널리 알려진 친숙한 명곡 위주로 선정해주세요.",
    balanced: "유명한 곡과 음악사적으로 의미 있는 곡을 적절히 섞어주세요.",
    obscure: "음악 애호가들 사이에서만 알려진 숨겨진 보석 같은 곡들을 발굴해주세요."
  }[filters?.discoveryMode || 'balanced'];

  let strictFilterInstructions = "";
  if (filters?.composer) {
    strictFilterInstructions += `\n[CRITICAL CONSTRAINT] 모든 후보곡의 작곡가는 반드시 '${filters.composer}'여야 합니다.`;
  }
  if (filters?.performer) {
    strictFilterInstructions += `\n[CRITICAL CONSTRAINT] 모든 후보곡은 반드시 '${filters.performer}'의 연주 버전이어야 합니다.`;
  }
  if (filters?.era) {
    strictFilterInstructions += `\n[ERA CONSTRAINT] 곡의 시대 배경은 반드시 '${filters.era}'여야 합니다.`;
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `오늘은 ${date}입니다. 클래식 음악 큐레이션을 위해 후보곡 3개를 추천해주세요.

               [필터 조건]
               1. ${modeInstruction}
               2. 분위기(Mood): ${filters?.mood || "자유로운 분위기"}
               ${strictFilterInstructions}

               [데이터 품질 요구사항]
               - 입력된 필터(작곡가, 연주자)가 있다면 절대적으로 준수하세요.
               - 유튜브 검색어(youtubeQuery)는 [작곡가 + 곡 제목 + 연주자 이름] 형식으로 생성하세요.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            composer: { type: Type.STRING },
            title: { type: Type.STRING },
            year: { type: Type.STRING },
            era: { type: Type.STRING },
            performer: { type: Type.STRING },
            description: { type: Type.STRING },
            mood: { type: Type.STRING },
            funFact: { type: Type.STRING },
            youtubeQuery: { type: Type.STRING },
          },
          required: ["composer", "title", "year", "era", "performer", "description", "mood", "funFact", "youtubeQuery"]
        }
      }
    }
  });

  const candidates: any[] = JSON.parse(response.text || "[]");
  return candidates.map((data, index) => ({
    id: btoa(date + data.title + index + (filters?.composer || "")),
    date,
    ...data,
    imageUrl: `https://picsum.photos/seed/${encodeURIComponent(data.composer + index)}/800/600`
  }));
};

import React, { useState, useEffect } from 'react';
import { ClassicalPiece } from '../types';
import { getInspirations, CurationInspiration } from '../services/geminiService';
import { Sparkles, Check, Copy, MessageCircle, Mail, Edit3, Youtube, Music, Search, Filter, RefreshCw, Compass, Layers, User, Lightbulb, Zap } from 'lucide-react';

interface CuratorWorkplaceProps {
  candidates: ClassicalPiece[];
  onConfirm: (piece: ClassicalPiece) => void;
  onSearch: (composer: string, mood: string, discoveryMode: string, era: string, performer: string) => void;
  isSearching: boolean;
}

export const CuratorWorkplace: React.FC<CuratorWorkplaceProps> = ({ candidates, onConfirm, onSearch, isSearching }) => {
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [editedText, setEditedText] = useState("");
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);

  const [searchComposer, setSearchComposer] = useState("");
  const [searchMood, setSearchMood] = useState("");
  const [searchPerformer, setSearchPerformer] = useState("");
  const [discoveryMode, setDiscoveryMode] = useState("balanced");
  const [era, setEra] = useState("");

  const [inspirations, setInspirations] = useState<CurationInspiration[]>([]);
  const [loadingInspirations, setLoadingInspirations] = useState(false);

  useEffect(() => {
    loadInspirations();
  }, []);

  const loadInspirations = async () => {
    setLoadingInspirations(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const items = await getInspirations(today);
      setInspirations(items);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingInspirations(false);
    }
  };

  const handleApplyInspiration = (ins: CurationInspiration) => {
    setSearchComposer(ins.filters.composer || "");
    setSearchPerformer(ins.filters.performer || "");
    setSearchMood(ins.filters.mood || "");
    setDiscoveryMode(ins.filters.discoveryMode || "balanced");
    setEra(ins.filters.era || "");

    // 즉시 검색 실행
    onSearch(
      ins.filters.composer || "",
      ins.filters.mood || "",
      ins.filters.discoveryMode || "balanced",
      ins.filters.era || "",
      ins.filters.performer || ""
    );
  };

  const handleSelect = (idx: number) => {
    setSelectedIdx(idx);
    const piece = candidates[idx];
    setEditedText(`${piece.composer} - ${piece.title}\n[추천 연주: ${piece.performer}]\n\n[곡 설명]\n${piece.description}\n\n[알고 들으면 더 좋은 사실]\n${piece.funFact}`);
  };

  const handleFilterSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSelectedIdx(null);
    onSearch(searchComposer, searchMood, discoveryMode, era, searchPerformer);
  };

  const showFeedback = (msg: string) => {
    setCopyFeedback(msg);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-1000">
      {/* 1단계: AI 영감 제안 섹션 */}
      <section>
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center space-x-2">
            <Lightbulb className="w-5 h-5 text-amber-500" />
            <h3 className="text-xl font-serif font-bold text-amber-950">오늘의 큐레이션 아이디어</h3>
          </div>
          <button 
            onClick={loadInspirations}
            className="text-xs font-bold text-amber-700/50 hover:text-amber-700 flex items-center"
          >
            <RefreshCw className={`w-3 h-3 mr-1 ${loadingInspirations ? 'animate-spin' : ''}`} />
            새 아이디어 받기
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {loadingInspirations ? (
            [1, 2, 3].map(i => <div key={i} className="h-24 bg-amber-50 rounded-2xl animate-pulse" />)
          ) : (
            inspirations.map((ins, i) => (
              <div 
                key={i}
                onClick={() => handleApplyInspiration(ins)}
                className="group p-5 bg-white border border-amber-100 rounded-2xl cursor-pointer hover:border-amber-500 hover:shadow-lg transition-all relative overflow-hidden"
              >
                <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:opacity-20 transition-opacity">
                    <Zap className="w-12 h-12 text-amber-900" />
                </div>
                <h4 className="text-sm font-black text-amber-900 mb-1 group-hover:text-amber-600 transition-colors">{ins.theme}</h4>
                <p className="text-[11px] text-amber-800/60 line-clamp-2 leading-relaxed">{ins.reason}</p>
                <div className="mt-3 flex items-center text-[9px] font-bold text-amber-500 uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity">
                  이 테마로 즉시 검색 <Sparkles className="w-3 h-3 ml-1" />
                </div>
              </div>
            ))
          )}
        </div>
      </section>

      {/* 2단계: 정밀 필터링 섹션 */}
      <section className="bg-white p-8 rounded-[2.5rem] border border-amber-100 shadow-xl overflow-hidden relative">
        <form onSubmit={handleFilterSubmit} className="space-y-8 relative z-10">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-amber-900 tracking-widest flex items-center">
                <Search className="w-3 h-3 mr-1" /> 작곡가
              </label>
              <input 
                type="text"
                value={searchComposer}
                onChange={(e) => setSearchComposer(e.target.value)}
                placeholder="예: 베토벤, 리스트..."
                className="w-full px-4 py-3 bg-amber-50/50 border border-amber-100 rounded-xl focus:outline-none focus:ring-2 focus:ring-amber-500 transition text-sm"
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-amber-900 tracking-widest flex items-center">
                <User className="w-3 h-3 mr-1" /> 연주자
              </label>
              <input 
                type="text"
                value={searchPerformer}
                onChange={(e) => setSearchPerformer(e.target.value)}
                placeholder="예: 조성진, 랑랑..."
                className="w-full px-4 py-3 bg-amber-50/50 border border-amber-100 rounded-xl focus:outline-none focus:ring-2 focus:ring-amber-500 transition text-sm"
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-amber-900 tracking-widest flex items-center">
                <Filter className="w-3 h-3 mr-1" /> 무드
              </label>
              <input 
                type="text"
                value={searchMood}
                onChange={(e) => setSearchMood(e.target.value)}
                placeholder="예: 열정적인, 서정적인..."
                className="w-full px-4 py-3 bg-amber-50/50 border border-amber-100 rounded-xl focus:outline-none focus:ring-2 focus:ring-amber-500 transition text-sm"
              />
            </div>
          </div>

          <div className="flex flex-wrap gap-2 pt-2 border-t border-amber-50">
            <span className="text-[10px] font-bold text-amber-800/40 uppercase tracking-widest mr-2 py-2">Quick Tags:</span>
            {["쇼팽", "모차르트", "조성진", "임윤찬", "베를린 필", "바이올린", "협주곡"].map(tag => (
              <button
                key={tag}
                type="button"
                onClick={() => {
                   if (tag.includes("필") || ["조성진", "임윤찬"].includes(tag)) setSearchPerformer(tag);
                   else setSearchComposer(tag);
                }}
                className="px-3 py-1 bg-amber-50 text-amber-800 text-xs rounded-full border border-amber-100 hover:bg-amber-100 transition"
              >
                #{tag}
              </button>
            ))}
          </div>

          <button 
            type="submit"
            disabled={isSearching}
            className="w-full bg-amber-950 text-white py-4 rounded-xl font-bold hover:bg-black transition flex items-center justify-center space-x-2 shadow-lg disabled:opacity-50"
          >
            {isSearching ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5 text-amber-400" />}
            <span className="text-lg">{isSearching ? "라이브러리 정밀 검색 중..." : "AI 라이브러리에서 곡 발굴하기"}</span>
          </button>
        </form>
      </section>

      {/* 후보곡 리스트 섹션 */}
      <section>
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center space-x-3">
            <div className="p-2 bg-amber-100 rounded-lg">
                <Music className="w-6 h-6 text-amber-900" />
            </div>
            <h2 className="text-3xl font-serif font-bold text-amber-950">선별된 큐레이션 후보</h2>
          </div>
        </div>

        {isSearching ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {[1, 2, 3].map(i => (
              <div key={i} className="bg-amber-50 h-80 rounded-3xl animate-pulse flex items-center justify-center">
                <Search className="w-8 h-8 text-amber-200 animate-bounce" />
              </div>
            ))}
          </div>
        ) : candidates.length === 0 ? (
          <div className="py-20 text-center border-2 border-dashed border-amber-100 rounded-3xl">
             <Compass className="w-12 h-12 text-amber-200 mx-auto mb-4" />
             <p className="text-amber-800/40 font-serif italic">필터를 설정하고 곡을 발굴해보세요.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {candidates.map((p, i) => (
              <div 
                key={p.id}
                onClick={() => handleSelect(i)}
                className={`cursor-pointer group relative bg-white rounded-3xl overflow-hidden border-2 transition-all duration-500 hover:shadow-2xl
                  ${selectedIdx === i ? 'border-amber-500 ring-4 ring-amber-100' : 'border-transparent shadow-md hover:border-amber-200'}`}
              >
                <div className="h-48 relative overflow-hidden">
                  <img src={p.imageUrl} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" alt={p.composer} />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent opacity-60" />
                  {selectedIdx === i && (
                    <div className="absolute inset-0 bg-amber-500/20 flex items-center justify-center">
                      <div className="bg-white p-2 rounded-full shadow-xl animate-in zoom-in">
                        <Check className="w-6 h-6 text-amber-600" />
                      </div>
                    </div>
                  )}
                </div>
                <div className="p-6">
                  <p className="text-xs font-bold text-amber-600 mb-1">{p.composer}</p>
                  <h4 className="font-bold text-amber-950 line-clamp-1 leading-tight mb-1 text-lg">{p.title}</h4>
