import { GoogleGenAI, Type } from "@google/genai";
import { ClassicalPiece } from "../types";

export interface CurationFilters {
  composer?: string;
  mood?: string;
  performer?: string;
  occasion?: string;
  instrumentation?: string;
  discoveryMode?: 'popular' | 'balanced' | 'obscure';
  era?: string;
}

export interface CurationInspiration {
  theme: string;
  reason: string;
  filters: CurationFilters;
}

export const getInspirations = async (date: string): Promise<CurationInspiration[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `오늘은 ${date}입니다. 클래식 음악 큐레이터를 위해 오늘 시도해볼만한 매력적인 큐레이션 테마 3가지를 제안해주세요. 
               단순한 작곡가 위주가 아니라 '상황(Occasion)'이나 '특정 악기의 질감'을 강조한 테마를 포함해주세요.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            theme: { type: Type.STRING },
            reason: { type: Type.STRING },
            filters: {
              type: Type.OBJECT,
              properties: {
                composer: { type: Type.STRING },
                performer: { type: Type.STRING },
                mood: { type: Type.STRING },
                occasion: { type: Type.STRING },
                instrumentation: { type: Type.STRING },
                era: { type: Type.STRING },
                discoveryMode: { type: Type.STRING }
              }
            }
          },
          required: ["theme", "reason", "filters"]
        }
      }
    }
  });

  return JSON.parse(response.text || "[]");
};

export const generateCandidates = async (date: string, filters?: CurationFilters): Promise<ClassicalPiece[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const modeInstruction = {
    popular: "대중적으로 널리 알려진 친숙한 명곡 위주로 선정해주세요.",
    balanced: "유명한 곡과 음악사적으로 의미 있는 곡을 적절히 섞어주세요.",
    obscure: "음악 애호가들 사이에서만 알려진 숨겨진 보석 같은 곡들을 발굴해주세요."
  }[filters?.discoveryMode || 'balanced'];

  let strictFilterInstructions = "";
  if (filters?.composer) strictFilterInstructions += `\n- 작곡가: 반드시 '${filters.composer}'여야 함.`;
  if (filters?.performer) strictFilterInstructions += `\n- 연주자: 반드시 '${filters.performer}'의 연주여야 함.`;
  if (filters?.occasion) strictFilterInstructions += `\n- 상황/장면: '${filters.occasion}' 상황에 완벽히 어울리는 선곡이어야 함.`;
  if (filters?.instrumentation) strictFilterInstructions += `\n- 악기/구성: '${filters.instrumentation}' 위주의 곡이어야 함.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `오늘은 ${date}입니다. 아래 필터 조건에 맞춰 클래식 음악 후보곡 3개를 추천해주세요.

               [필터 및 제약 조건]
               1. ${modeInstruction}
               2. 분위기(Mood): ${filters?.mood || "자유로운 분위기"}
               ${strictFilterInstructions}

               [설명 작성 지침]
               - '상황/장면' 필터가 있다면, 왜 이 곡이 그 상황에 어울리는지 음악적 특징(템포, 선율 등)을 들어 구체적으로 설명하세요.
               - 유튜브 검색어(youtubeQuery)는 [작곡가 + 곡 제목 + 연주자] 형식으로 생성하세요.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            composer: { type: Type.STRING },
            title: { type: Type.STRING },
            year: { type: Type.STRING },
            era: { type: Type.STRING },
            performer: { type: Type.STRING },
            description: { type: Type.STRING },
            mood: { type: Type.STRING },
            funFact: { type: Type.STRING },
            youtubeQuery: { type: Type.STRING },
          },
          required: ["composer", "title", "year", "era", "performer", "description", "mood", "funFact", "youtubeQuery"]
        }
      }
    }
  });

  const candidates: any[] = JSON.parse(response.text || "[]");
  return candidates.map((data, index) => ({
    id: btoa(date + data.title + index),
    date,
    ...data,
    imageUrl: `https://picsum.photos/seed/${encodeURIComponent(data.composer + index)}/800/600`
  }));
};

export const generateMaestroResponse = async (userComment: string, pieceContext: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `당신은 클래식 음악의 대가인 '마에스트로'입니다. 
               오늘의 곡(${pieceContext})에 대해 사용자가 남긴 감상(${userComment})에 대해 
               정중하고 지적인 어조로 짧은 화답(2-3문장)을 남겨주세요. 
               음악적 통찰력을 포함하되 격식 있는 한국어(하십시오체 등)를 사용하세요.`,
  });
  return response.text || "음악은 영혼의 언어입니다. 당신의 감상에 깊이 공감합니다.";
};

