                className="flex items-center space-x-1.5 px-3 py-1.5 rounded-full bg-amber-50 text-amber-700 hover:bg-amber-100 transition"
              >
                <ThumbsUp className="w-3.5 h-3.5" />
                <span className="text-xs font-black">{post.likes}</span>
