import React, { useState, useEffect } from 'react';
import { Performance } from '../types';
import { getUpcomingPerformances } from '../services/geminiService';
import { Calendar, MapPin, User, ExternalLink, Loader2, Ticket, Search, Heart, Check } from 'lucide-react';

interface PerformanceInfoProps {
  onSave: (p: Performance) => void;
  isSaved: (id: string) => boolean;
}

export const PerformanceInfo: React.FC<PerformanceInfoProps> = ({ onSave, isSaved }) => {
  const [performances, setPerformances] = useState<Performance[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [isSearching, setIsSearching] = useState(false);

  const fetchPerformances = async (query: string = "") => {
    if (query) setIsSearching(true);
    else setLoading(true);

    try {
      const today = new Date().toISOString().split('T')[0];
      const data = await getUpcomingPerformances(today, query);
      setPerformances(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
      setIsSearching(false);
    }
  };

  useEffect(() => {
    fetchPerformances();
  }, []);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    fetchPerformances(searchQuery);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-12 animate-in fade-in duration-1000">
      <div className="text-center space-y-4">
        <h2 className="text-4xl font-serif font-bold text-amber-950">공연 정보 탐색</h2>
        <p className="text-amber-800/60 italic">당신의 도시에서 울려 퍼질 클래식의 감동</p>
      </div>

      <div className="bg-white p-8 rounded-[2.5rem] border border-amber-100 shadow-xl">
        <form onSubmit={handleSearch} className="flex flex-col md:flex-row gap-4">
          <div className="relative flex-grow">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-amber-400" />
            <input 
              type="text" 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="도시, 작곡가, 연주자 이름으로 검색 (예: 서울 조성진)" 
              className="w-full pl-12 pr-4 py-4 bg-amber-50/50 border border-amber-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-amber-500 font-medium" 
            />
          </div>
          <button 
            type="submit"
            disabled={isSearching}
            className="px-8 py-4 bg-amber-950 text-white rounded-2xl font-black hover:bg-black transition shadow-lg flex items-center justify-center space-x-2"
          >
            {isSearching ? <Loader2 className="w-5 h-5 animate-spin" /> : <Search className="w-5 h-5" />}
            <span>{isSearching ? "검색 중..." : "공연 찾기"}</span>
          </button>
        </form>
      </div>

      {loading ? (
        <div className="flex flex-col items-center py-24 space-y-4">
          <Loader2 className="w-10 h-10 text-amber-700 animate-spin" />
          <p className="text-amber-800/40 serif italic">국내외 공연 일정을 불러오는 중입니다...</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-8">
          {performances.map((p) => (
            <div key={p.id} className="bg-white rounded-[2.5rem] overflow-hidden shadow-xl border border-amber-100 flex flex-col md:flex-row group hover:shadow-2xl transition-all duration-500">
              <div className="md:w-64 h-64 relative overflow-hidden flex-shrink-0">
                <img src={p.imageUrl} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" alt={p.title} />
                <div className="absolute inset-0 bg-black/20 group-hover:bg-transparent transition-colors" />
                <button 
                  onClick={() => onSave(p)}
                  className={`absolute top-4 right-4 p-3 rounded-full shadow-lg transition-all transform active:scale-90
                    ${isSaved(p.id) ? 'bg-amber-500 text-white' : 'bg-white/90 text-amber-900 hover:bg-amber-500 hover:text-white'}`}
                >
                  {isSaved(p.id) ? <Check className="w-5 h-5" /> : <Heart className="w-5 h-5" />}
                </button>
              </div>
              <div className="p-8 flex flex-col justify-between flex-grow">
                <div className="space-y-4">
                  <div className="flex items-center space-x-2 text-amber-600">
                    <Calendar className="w-4 h-4" />
                    <span className="text-sm font-bold uppercase tracking-tighter">{p.date}</span>
                  </div>
                  <h3 className="text-2xl font-bold text-amber-950 serif leading-tight">{p.title}</h3>
                  <div className="flex flex-wrap gap-4 text-xs font-medium text-amber-800/70">
                    <span className="flex items-center"><MapPin className="w-3.5 h-3.5 mr-1.5" /> {p.venue}</span>
                    <span className="flex items-center"><User className="w-3.5 h-3.5 mr-1.5" /> {p.performer}</span>
                  </div>
                </div>
                <div className="mt-8 flex items-center justify-between border-t border-amber-50 pt-6">
                    <div className="flex items-center space-x-2">
                        <Ticket className="w-4 h-4 text-amber-300" />
                        <span className="text-[10px] font-black uppercase tracking-widest text-amber-400">Tickets Available</span>
                    </div>
                    <a 
                      href={p.link} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="flex items-center space-x-2 px-6 py-2.5 bg-amber-950 text-white rounded-xl font-bold hover:bg-black transition text-sm shadow-md"
                    >
                      <span>상세 정보</span>
                      <ExternalLink className="w-3.5 h-3.5" />
                    </a>
                </div>
              </div>
            </div>
          ))}
          {performances.length === 0 && (
            <div className="text-center py-24 bg-amber-50/20 rounded-[2.5rem] border-2 border-dashed border-amber-100">
              <Search className="w-12 h-12 text-amber-200 mx-auto mb-4" />
              <p className="text-amber-800/40 serif italic text-lg">검색 조건에 맞는 공연을 찾을 수 없습니다.</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

