        <div className="p-10 space-y-6">
          <div className="grid grid-cols-2 gap-4">
            <button 
              onClick={() => handleSocialLogin('Kakao')}
              className="flex items-center justify-center space-x-2 py-3 bg-[#FEE500] text-[#3c1e1e] rounded-xl font-bold text-sm hover:opacity-90 transition"
            >
              <span className="w-4 h-4 bg-[#3c1e1e] rounded-full flex items-center justify-center text-[8px] text-[#FEE500]">K</span>
