          <div className="relative flex items-center">
            <div className="flex-grow border-t border-amber-100"></div>
            <span className="flex-shrink mx-4 text-xs text-amber-400 font-bold uppercase tracking-widest">or email</span>
            <div className="flex-grow border-t border-amber-100"></div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            {isRegister && (
              <div className="relative">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-amber-400" />
                <input 
                  type="text" required placeholder="사용자 이름" 
                  value={username} onChange={(e) => setUsername(e.target.value)}
                  className="w-full pl-12 pr-4 py-3.5 bg-amber-50/50 border border-amber-100 rounded-xl focus:outline-none focus:ring-2 focus:ring-amber-500 text-sm"
                />
