            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-amber-400" />
              <input 
                type="password" required placeholder="비밀번호" 
                value={password} onChange={(e) => setPassword(e.target.value)}
