              />
            </div>

            <button type="submit" className="w-full py-4 bg-amber-950 text-white rounded-xl font-black hover:bg-black transition-all shadow-xl flex items-center justify-center space-x-2">
              <span>{isRegister ? "가입하고 혜택받기" : "로그인하기"}</span>
              <Sparkles className="w-4 h-4 text-amber-400" />
            </button>
          </form>

          <div className="text-center">
            <button 
              type="button" 
              onClick={() => setIsRegister(!isRegister)}
