export const RecommendationCard: React.FC<RecommendationCardProps> = ({ piece, tier, onUpgrade, onSave, isSaved }) => {
  const [copied, setCopied] = useState(false);
  const isPremium = tier === SubscriptionTier.PREMIUM;

  const handleShare = async () => {
    const shareText = `[ClassicDaily] ${piece.composer} - ${piece.title}\nListen: https://www.youtube.com/results?search_query=${encodeURIComponent(piece.youtubeQuery)}`;
    if (navigator.share) {
      try { await navigator.share({ title: 'ClassicDaily', text: shareText, url: window.location.href }); } catch (err) {}
    } else {
      navigator.clipboard.writeText(shareText);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-1000 max-w-4xl mx-auto">
      <div className={`bg-white rounded-[2rem] overflow-hidden shadow-2xl border ${isPremium ? 'border-amber-200 shadow-amber-900/5' : 'border-stone-100'}`}>

        {/* Abstract Header Section - No Image */}
        <div className="relative p-8 md:p-16 bg-stone-900 overflow-hidden min-h-[400px] flex flex-col justify-end">
          <div className="absolute top-0 right-0 w-full h-full opacity-10 pointer-events-none">
            <div className="absolute top-[-20%] right-[-10%] w-[80%] h-[120%] border border-amber-400/20 rounded-full rotate-45" />
            <div className="absolute bottom-[-10%] left-[-10%] w-[60%] h-[60%] border border-amber-400/10 rounded-full" />
          </div>

          <div className="relative z-10 flex justify-between items-end gap-8">
            <div className="flex-grow">
              <div className="flex items-center space-x-3 mb-6">
                <span className="px-3 py-1 bg-amber-400 text-stone-900 text-[10px] font-black uppercase tracking-widest rounded-full">
                  {piece.era}
                </span>
                <span className="text-stone-400 text-[10px] font-black uppercase tracking-widest">
                  Est. {piece.year}
                </span>
              </div>
              <h2 className="text-4xl md:text-7xl text-white font-serif font-bold leading-[1.1] mb-4">
                {piece.title}
              </h2>
              <p className="text-2xl md:text-4xl text-amber-400 serif italic">
                {piece.composer}
              </p>
            </div>

            <button 
              onClick={() => onSave(piece)}
              className={`p-5 rounded-full shadow-2xl transition-all transform hover:scale-110 active:scale-95 mb-2
                ${isSaved(piece.id) ? 'bg-amber-400 text-stone-900' : 'bg-white/10 text-white hover:bg-white/20 border border-white/20'}`}
            >
              <Heart className={`w-8 h-8 ${isSaved(piece.id) ? 'fill-current' : ''}`} />
            </button>
          </div>
        </div>

        <div className="p-8 md:p-16 grid grid-cols-1 lg:grid-cols-3 gap-16">
          <div className="lg:col-span-2 space-y-12">

            <section className="flex items-center space-x-6">
              <div className="w-16 h-16 bg-stone-100 rounded-2xl flex items-center justify-center text-stone-900 shadow-inner">
                <User className="w-8 h-8" />
              </div>
              <div>
                <p className="text-[10px] font-black uppercase text-stone-400 tracking-widest mb-1">Recommended Soloist</p>
                <h4 className="text-2xl font-bold text-stone-900">{piece.performer}</h4>
              </div>
            </section>

            <section>
              <div className="flex items-center space-x-3 text-stone-900 mb-8">
                <div className="w-1 h-8 bg-amber-400" />
                <h3 className="text-xs font-black uppercase tracking-[0.3em]">Program Notes</h3>
              </div>
              <p className="text-xl text-stone-900/80 leading-relaxed font-light first-letter:text-6xl first-letter:font-serif first-letter:text-stone-900 first-letter:mr-3 first-letter:float-left">
                {piece.description}
              </p>
            </section>

            <section className="relative">
              {!isPremium && (
                <div className="absolute inset-0 bg-white/40 backdrop-blur-md z-10 flex flex-col items-center justify-center p-8 text-center rounded-3xl border border-stone-200 shadow-xl">
                  <Lock className="w-12 h-12 text-stone-900 mb-4" />
                  <h4 className="text-xl font-bold text-stone-900 uppercase tracking-tight">Full Archive Access</h4>
                  <p className="text-sm text-stone-600 mb-8 max-w-xs">Premium members unlock historical context and deep-dive musical theory.</p>
                  <button onClick={onUpgrade} className="px-10 py-4 bg-stone-900 text-white rounded-full font-black uppercase tracking-widest text-xs hover:bg-black shadow-2xl transition">Unlock Premium</button>
                </div>
              )}
              <div className="bg-stone-50 p-10 rounded-3xl border border-stone-100">
                <div className="flex items-center space-x-3 text-stone-900 mb-6">
                  <Info className="w-5 h-5 text-amber-500" />
                  <h3 className="text-xs font-black uppercase tracking-widest">Maestro's Secret</h3>
                </div>
                <p className={`text-stone-900/80 italic leading-relaxed text-lg ${!isPremium ? 'blur-md select-none' : ''}`}>
                  {piece.funFact}
                </p>
              </div>
            </section>

            <div className="flex flex-wrap gap-4 pt-4">
              <a href={`https://www.youtube.com/results?search_query=${encodeURIComponent(piece.youtubeQuery)}`} target="_blank" rel="noopener noreferrer" className="flex items-center space-x-4 px-10 py-5 bg-stone-900 text-white rounded-full transition-all shadow-2xl hover:bg-black hover:-translate-y-1">
                <Play className="w-5 h-5 fill-amber-400 text-amber-400" />
                <span className="font-black uppercase tracking-widest text-sm">Listen Now</span>
              </a>
              <button onClick={handleShare} className="flex items-center space-x-2 px-8 py-5 border border-stone-200 text-stone-900 rounded-full transition font-black uppercase tracking-widest text-xs hover:bg-stone-50">
                {copied ? <Check className="w-5 h-5 text-green-600" /> : <Share2 className="w-5 h-5" />}
                <span>{copied ? 'Copied' : 'Share'}</span>
              </button>
            </div>
          </div>

          <div className="space-y-8">
             <div className="bg-stone-50 border border-stone-100 p-8 rounded-[2.5rem]">
                <h4 className="text-[10px] font-black text-stone-400 uppercase tracking-widest mb-6">Atmosphere</h4>
                <div className="flex flex-wrap gap-2">
                  {piece.mood.split(',').map((m, i) => (
                    <span key={i} className="px-4 py-2 bg-white text-stone-900 text-[10px] rounded-xl border border-stone-100 font-black uppercase tracking-wider">
                      {m.trim()}
                    </span>
                  ))}
                </div>
             </div>

             {!isPremium ? (
               <div className="bg-amber-400 text-stone-900 p-10 rounded-[2.5rem] shadow-2xl relative overflow-hidden group">
                  <Sparkles className="absolute -top-4 -right-4 w-24 h-24 text-stone-900/10 group-hover:rotate-12 transition-transform" />
                  <h4 className="text-[10px] font-black uppercase tracking-widest mb-4">Elite Tier</h4>
                  <h3 className="text-2xl font-serif font-bold mb-4 leading-tight">Elevate your listening experience.</h3>
                  <button onClick={onUpgrade} className="w-full py-4 bg-stone-900 text-white font-black rounded-xl hover:bg-black transition text-xs uppercase tracking-widest shadow-xl">
                    Join Now
                  </button>
               </div>
             ) : (
               <div className="bg-stone-900 text-amber-400 p-10 rounded-[2.5rem] text-center shadow-xl">
                  <Crown className="w-10 h-10 mx-auto mb-4" />
                  <h4 className="font-black uppercase tracking-[0.2em] text-xs">Premium Active</h4>
                  <p className="text-[11px] text-white/50 mt-4 italic font-medium">Curating the finest masterpieces at 24-bit fidelity.</p>
               </div>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Performance } from '../types';
import { getUpcomingPerformances } from '../services/geminiService';
import { Calendar, MapPin, User, ExternalLink, Loader2, Ticket, Search, Heart, Check, Music } from 'lucide-react';

interface PerformanceInfoProps {
  onSave: (p: Performance) => void;
  isSaved: (id: string) => boolean;
}

export const PerformanceInfo: React.FC<PerformanceInfoProps> = ({ onSave, isSaved }) => {
  const [performances, setPerformances] = useState<Performance[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [isSearching, setIsSearching] = useState(false);

  const fetchPerformances = async (query: string = "") => {
    if (query) setIsSearching(true);
    else setLoading(true);

    try {
      const today = new Date().toISOString().split('T')[0];
      const data = await getUpcomingPerformances(today, query);
      setPerformances(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
      setIsSearching(false);
    }
  };

  useEffect(() => {
    fetchPerformances();
  }, []);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    fetchPerformances(searchQuery);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-12 animate-in fade-in duration-1000">
      <div className="text-center space-y-4">
        <h2 className="text-4xl md:text-5xl font-serif font-bold text-stone-900">Upcoming Concerts</h2>
        <p className="text-stone-400 italic text-lg serif uppercase tracking-widest text-[11px]">Experience the Masterpieces Live</p>
      </div>

      <div className="bg-white p-8 rounded-[2.5rem] border border-stone-100 shadow-xl">
        <form onSubmit={handleSearch} className="flex flex-col md:flex-row gap-4">
          <div className="relative flex-grow">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-stone-400" />
            <input 
              type="text" 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search by city, composer, or artist..." 
              className="w-full pl-16 pr-6 py-5 bg-stone-50 border border-stone-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-stone-900 font-medium placeholder:text-stone-300" 
            />
          </div>
          <button 
            type="submit"
            disabled={isSearching}
            className="px-10 py-5 bg-stone-900 text-white rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-black transition shadow-lg flex items-center justify-center space-x-3"
          >
            {isSearching ? <Loader2 className="w-5 h-5 animate-spin" /> : <Search className="w-5 h-5" />}
            <span>{isSearching ? "Searching..." : "Find Concerts"}</span>
          </button>
        </form>
      </div>

      {loading ? (
        <div className="flex flex-col items-center py-32 space-y-6">
          <Loader2 className="w-12 h-12 text-stone-300 animate-spin" />
          <p className="text-stone-400 text-[10px] font-black uppercase tracking-[0.3em]">Accessing Global Concert Database</p>
        </div>
      ) : (
        <div className="space-y-6">
          {performances.map((p) => (
            <div key={p.id} className="bg-white rounded-[2rem] overflow-hidden shadow-sm border border-stone-100 flex flex-col md:flex-row group hover:shadow-xl hover:border-amber-200 transition-all duration-500">
              <div className="md:w-48 h-48 md:h-auto bg-stone-900 flex items-center justify-center text-amber-400 relative overflow-hidden flex-shrink-0">
                <Music className="w-16 h-16 opacity-20" />
                <div className="absolute inset-0 flex items-center justify-center">
                   <div className="text-center">
                     <span className="block text-[32px] font-serif font-bold text-white mb-1">{p.date.split('-')[2] || '??'}</span>
                     <span className="block text-[10px] font-black uppercase tracking-widest opacity-60">Sept</span>
                   </div>
                </div>
              </div>
              <div className="p-10 flex flex-col justify-between flex-grow">
                <div className="space-y-4">
                  <div className="flex items-center space-x-3">
                    <span className="px-2 py-1 bg-stone-100 text-stone-600 text-[9px] font-black uppercase tracking-widest rounded">
                      Live Performance
                    </span>
                  </div>
                  <h3 className="text-2xl font-bold text-stone-900 serif">{p.title}</h3>
                  <div className="grid grid-cols-2 gap-4 text-[11px] font-bold text-stone-400 uppercase tracking-widest">
                    <span className="flex items-center"><MapPin className="w-4 h-4 mr-2 text-stone-200" /> {p.venue}</span>
                    <span className="flex items-center"><User className="w-4 h-4 mr-2 text-stone-200" /> {p.performer}</span>
                  </div>
                </div>
                <div className="mt-10 flex items-center justify-between border-t border-stone-50 pt-8">
                    <button 
                      onClick={() => onSave(p)}
                      className={`flex items-center space-x-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition
                        ${isSaved(p.id) ? 'text-amber-500' : 'text-stone-300 hover:text-stone-900'}`}
                    >
                      {isSaved(p.id) ? <Check className="w-4 h-4" /> : <Heart className="w-4 h-4" />}
                      <span>{isSaved(p.id) ? 'Saved' : 'Save Event'}</span>
                    </button>
                    <a 
                      href={p.link} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="flex items-center space-x-3 px-8 py-3 bg-stone-900 text-white rounded-xl font-black uppercase tracking-widest text-[10px] hover:bg-black transition shadow-md"
                    >
                      <span>Get Details</span>
                      <ExternalLink className="w-3.5 h-3.5" />
                    </a>
                </div>
              </div>
            </div>
          ))}
          {performances.length === 0 && (
            <div className="text-center py-32 bg-stone-50/50 rounded-[3rem] border-2 border-dashed border-stone-100">
              <Search className="w-12 h-12 text-stone-200 mx-auto mb-6" />
              <p className="text-stone-400 font-serif italic text-lg">No concerts match your inquiry.</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Navbar } from './components/Navbar';
import { RecommendationCard } from './components/RecommendationCard';
import { HistoryList } from './components/HistoryList';
import { SubscriptionForm } from './components/SubscriptionForm';
import { PricingSection } from './components/PricingSection';
import { AdminPanel } from './components/AdminPanel';
import { CuratorWorkplace } from './components/CuratorWorkplace';
import { CommunityBoard } from './components/CommunityBoard';
import { PerformanceInfo } from './components/PerformanceInfo';
import { MyCollection } from './components/MyCollection';
import { AuthModal } from './components/AuthModal';
import { PaymentModal } from './components/PaymentModal';
import { generateCandidates } from './services/geminiService';
import { ClassicalPiece, ViewState, SubscriptionTier, UserAccount, Performance } from './types';
import { Loader2, User, Crown, Music } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.CURATE);
  const [tier, setTier] = useState<SubscriptionTier>(SubscriptionTier.FREE);
  const [todayPiece, setTodayPiece] = useState<ClassicalPiece | null>(null);
  const [candidates, setCandidates] = useState<ClassicalPiece[]>([]);
  const [history, setHistory] = useState<ClassicalPiece[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [isSearching, setIsSearching] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const [savedPieces, setSavedPieces] = useState<ClassicalPiece[]>([]);
  const [savedPerformances, setSavedPerformances] = useState<Performance[]>([]);

  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  const fetchCurationData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const today = new Date().toISOString().split('T')[0];
      const savedPiece = localStorage.getItem(`classic_daily_${today}`);

      if (savedPiece) {
        setTodayPiece(JSON.parse(savedPiece));
      } else {
        const results = await generateCandidates(today);
        setCandidates(results);
      }
    } catch (err) {
      console.error(err);
      setError("AI library sync failed. Please check your connection.");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchCurationData();
    const savedHistory = localStorage.getItem('classic_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedUser = localStorage.getItem('classic_user');
    if (savedUser) {
      const user = JSON.parse(savedUser);
      setCurrentUser(user);
      const savedTier = localStorage.getItem(`tier_${user.email}`);
      if (savedTier) setTier(savedTier as SubscriptionTier);
    }

    const sp = localStorage.getItem('saved_pieces');
    if (sp) setSavedPieces(JSON.parse(sp));
    const spf = localStorage.getItem('saved_performances');
    if (spf) setSavedPerformances(JSON.parse(spf));
  }, [fetchCurationData]);

  const toggleSavePiece = (piece: ClassicalPiece) => {
    let updated;
    if (savedPieces.some(p => p.id === piece.id)) {
      updated = savedPieces.filter(p => p.id !== piece.id);
    } else {
      updated = [piece, ...savedPieces];
    }
    setSavedPieces(updated);
    localStorage.setItem('saved_pieces', JSON.stringify(updated));
  };

  const toggleSavePerformance = (perf: Performance) => {
    let updated;
    if (savedPerformances.some(p => p.id === perf.id)) {
      updated = savedPerformances.filter(p => p.id !== perf.id);
    } else {
      updated = [perf, ...savedPerformances];
    }
    setSavedPerformances(updated);
    localStorage.setItem('saved_performances', JSON.stringify(updated));
  };

  const handleCustomSearch = async (composer: string, mood: string, discoveryMode: any, era: string, performer: string, occasion: string, instrumentation: string) => {
    setIsSearching(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const results = await generateCandidates(today, { composer, mood, discoveryMode, era, performer, occasion, instrumentation });
      setCandidates(results);
    } catch (err) {
      console.error(err);
      alert("Error finding matching pieces.");
    } finally {
      setIsSearching(false);
    }
  };

  const handleConfirmPiece = (piece: ClassicalPiece) => {
    const today = new Date().toISOString().split('T')[0];
    setTodayPiece(piece);
    localStorage.setItem(`classic_daily_${today}`, JSON.stringify(piece));

    const existingHistoryRaw = localStorage.getItem('classic_history');
    const existingHistory = existingHistoryRaw ? JSON.parse(existingHistoryRaw) : [];
    const updatedHistory = [piece, ...existingHistory.filter((p: any) => p.id !== piece.id)].slice(0, 10);
    localStorage.setItem('classic_history', JSON.stringify(updatedHistory));
    setHistory(updatedHistory);

    setCurrentView(ViewState.HOME);
  };

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    localStorage.setItem('classic_user', JSON.stringify(user));
    const savedTier = localStorage.getItem(`tier_${user.email}`);
    if (savedTier) setTier(savedTier as SubscriptionTier);
    else setTier(SubscriptionTier.FREE);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setTier(SubscriptionTier.FREE);
    localStorage.removeItem('classic_user');
  };

  const handleUpgradeSuccess = () => {
    if (!currentUser) return;
    setTier(SubscriptionTier.PREMIUM);
    localStorage.setItem(`tier_${currentUser.email}`, SubscriptionTier.PREMIUM);
  };

  const renderContent = () => {
    if (loading) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-8 text-center">
          <Loader2 className="w-12 h-12 text-stone-900 animate-spin" />
          <p className="text-[11px] font-black uppercase tracking-[0.4em] text-stone-400">
            Synthesizing Global Musical Archives
          </p>
        </div>
      );
    }

    if (error) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 space-y-6">
          <p className="text-stone-400 font-serif italic">{error}</p>
          <button onClick={fetchCurationData} className="px-10 py-4 bg-stone-900 text-white rounded-full font-black uppercase tracking-widest text-xs shadow-2xl">Retry Sync</button>
        </div>
      );
    }

    switch (currentView) {
      case ViewState.CURATE:
        return (
          <CuratorWorkplace 
            candidates={candidates} 
            onConfirm={handleConfirmPiece} 
            onSearch={handleCustomSearch}
            isSearching={isSearching}
          />
        );
      case ViewState.HOME:
        return todayPiece && (
          <RecommendationCard 
            piece={todayPiece} 
            tier={tier} 
            onUpgrade={() => setCurrentView(ViewState.PRICING)} 
            onSave={toggleSavePiece}
            isSaved={(id) => savedPieces.some(p => p.id === id)}
          />
        );
      case ViewState.PERFORMANCES:
        return (
          <PerformanceInfo 
            onSave={toggleSavePerformance}
            isSaved={(id) => savedPerformances.some(p => p.id === id)}
          />
        );
      case ViewState.MY_COLLECTION:
        return (
          <MyCollection 
            savedPieces={savedPieces}
            savedPerformances={savedPerformances}
            onRemovePiece={(id) => setSavedPieces(savedPieces.filter(p => p.id !== id))}
            onRemovePerformance={(id) => setSavedPerformances(savedPerformances.filter(p => p.id !== id))}
            onSelectPiece={(p) => { setTodayPiece(p); setCurrentView(ViewState.HOME); }}
          />
        );
      case ViewState.COMMUNITY:
        return <CommunityBoard currentUser={currentUser} onLoginRequest={() => setShowAuthModal(true)} />;
      case ViewState.HISTORY:
        return <HistoryList items={history} tier={tier} onSelect={(p) => { setTodayPiece(p); setCurrentView(ViewState.HOME); }} onUpgrade={() => setCurrentView(ViewState.PRICING)} />;
      case ViewState.PRICING:
        return <PricingSection currentTier={tier} onSelectPlan={() => currentUser ? setShowPaymentModal(true) : setShowAuthModal(true)} />;
      case ViewState.ADMIN:
        return <AdminPanel todayPiece={todayPiece} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#fcfaf7] text-stone-900">
      <Navbar activeView={currentView} setView={setCurrentView} tier={tier} />

      <main className="flex-grow container mx-auto px-6 py-16 max-w-6xl">
        <div className="mb-24 flex flex-col items-center">
          {currentUser && (
            <div className="mb-10 flex items-center space-x-4 bg-white px-6 py-3 rounded-full border border-stone-100 shadow-xl animate-in slide-in-from-top-4">
              <div className="w-8 h-8 bg-stone-900 rounded-full flex items-center justify-center text-[10px] text-amber-400 font-black">
                {tier === SubscriptionTier.PREMIUM ? <Crown className="w-4 h-4" /> : <User className="w-4 h-4" />}
              </div>
              <span className="text-xs font-black uppercase tracking-widest">{currentUser.username}</span>
              <div className="w-px h-4 bg-stone-100 mx-2"></div>
              <button onClick={handleLogout} className="text-[10px] font-black uppercase tracking-widest text-stone-300 hover:text-stone-900 transition">Logout</button>
            </div>
          )}

          <div className="inline-block px-5 py-2 bg-stone-900 text-amber-400 text-[10px] font-black uppercase tracking-[0.4em] rounded-full mb-8 shadow-xl">
            Intelligent Curation
          </div>
          <h1 className="text-6xl md:text-9xl font-bold text-stone-900 mb-6 tracking-tighter uppercase font-serif">ClassicDaily</h1>
          <p className="text-stone-400 italic text-xl md:text-2xl serif max-w-2xl text-center leading-relaxed">
            Curating the finest classical masterpieces from global archives, delivered daily to your soul.
          </p>
        </div>

        {renderContent()}
      </main>

      <footer className="bg-stone-900 text-stone-500 py-24 px-6 text-center border-t border-stone-800">
        <p className="text-lg font-serif italic mb-6 text-stone-300">"Where words fail, music speaks." — Hans Christian Andersen</p>
        <p className="text-[10px] font-black uppercase tracking-[0.5em] opacity-40">© 2025 ClassicDaily • Archive Collective</p>
      </footer>

      {showAuthModal && (
        <AuthModal 
          onClose={() => setShowAuthModal(false)} 
          onLogin={handleLogin}
        />
      )}

      {showPaymentModal && (
        <PaymentModal 
          onClose={() => setShowPaymentModal(false)} 
          onSuccess={handleUpgradeSuccess}
        />
      )}
    </div>
  );
};

