                <p className="text-xs font-bold text-stone-400 uppercase tracking-widest">{p.composer}</p>
                <div className="mt-8 flex items-center text-[10px] font-black uppercase tracking-widest text-stone-300 group-hover:text-stone-900 transition-colors">
                   {selectedIdx === i ? <Check className="w-4 h-4 mr-2" /> : <PenTool className="w-4 h-4 mr-2" />}
