            </div>
            <div className="flex flex-col justify-center space-y-12">
              <div className="space-y-6">
                <h4 className="text-[10px] font-black uppercase tracking-[0.4em] text-white/40">Distribution</h4>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <button onClick={() => { navigator.clipboard.writeText(editedText); showFeedback("Copied for Chat"); }} className="flex flex-col items-center justify-center space-y-3 p-10 bg-white/5 hover:bg-white/10 text-white rounded-[2rem] border border-white/10 transition-all transform hover:-translate-y-1">
                    <MessageCircle className="w-8 h-8 text-amber-400" />
                    <span className="text-[10px] font-black uppercase tracking-widest">Chat Copy</span>
                  </button>
                  <button onClick={() => { navigator.clipboard.writeText(editedText); showFeedback("Copied for Email"); }} className="flex flex-col items-center justify-center space-y-3 p-10 bg-white/5 hover:bg-white/10 text-white rounded-[2rem] border border-white/10 transition-all transform hover:-translate-y-1">
                    <Mail className="w-8 h-8 text-amber-400" />
                    <span className="text-[10px] font-black uppercase tracking-widest">Email Copy</span>
                  </button>
