              </div>
              <button onClick={() => onConfirm(candidates[selectedIdx])} className="w-full py-8 bg-amber-400 text-stone-900 font-black uppercase tracking-[0.4em] text-xs rounded-3xl hover:bg-white transition-all shadow-2xl">
