import React, { useState, useEffect } from 'react';
import { ClassicalPiece } from '../types';
import { getInspirations, CurationInspiration } from '../services/geminiService';
import { 
  Sparkles, Check, MessageCircle, Mail, Music, Search, 
  RefreshCw, Compass, Lightbulb, Zap, User, PenTool 
} from 'lucide-react';

interface CuratorWorkplaceProps {
  candidates: ClassicalPiece[];
  onConfirm: (piece: ClassicalPiece) => void;
  onSearch: (composer: string, mood: string, discoveryMode: string, era: string, performer: string, occasion: string, instrumentation: string) => void;
  isSearching: boolean;
}

export const CuratorWorkplace: React.FC<CuratorWorkplaceProps> = ({ candidates, onConfirm, onSearch, isSearching }) => {
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [editedText, setEditedText] = useState("");
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);

  const [searchComposer, setSearchComposer] = useState("");
  const [searchMood, setSearchMood] = useState("");
  const [searchPerformer, setSearchPerformer] = useState("");
  const [searchOccasion, setSearchOccasion] = useState("");
  const [searchInstrumentation, setSearchInstrumentation] = useState("");
  const [discoveryMode, setDiscoveryMode] = useState("balanced");
  const [era, setEra] = useState("");

  const [inspirations, setInspirations] = useState<CurationInspiration[]>([]);
  const [loadingInspirations, setLoadingInspirations] = useState(false);

  useEffect(() => {
    loadInspirations();
  }, []);

  const loadInspirations = async () => {
    setLoadingInspirations(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const items = await getInspirations(today);
      setInspirations(items);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingInspirations(false);
    }
  };

  const handleApplyInspiration = (ins: CurationInspiration) => {
    setSearchComposer(ins.filters.composer || "");
    setSearchPerformer(ins.filters.performer || "");
    setSearchMood(ins.filters.mood || "");
    setSearchOccasion(ins.filters.occasion || "");
    setSearchInstrumentation(ins.filters.instrumentation || "");
    setDiscoveryMode(ins.filters.discoveryMode || "balanced");
    setEra(ins.filters.era || "");

    onSearch(
      ins.filters.composer || "",
      ins.filters.mood || "",
      ins.filters.discoveryMode || "balanced",
      ins.filters.era || "",
      ins.filters.performer || "",
      ins.filters.occasion || "",
      ins.filters.instrumentation || ""
    );
  };

  const handleSelect = (i: number) => {
    setSelectedIdx(i);
    const p = candidates[i];
    setEditedText(`🎻 [Kyth Classical Daily Curation]\n\n✨ Masterpiece: ${p.composer} - ${p.title}\n🎹 Performed by: ${p.performer}\n\n[The Story]\n${p.description}\n\n[Maestro's Insight]\n${p.funFact}\n\n🎧 Listen: https://www.youtube.com/results?search_query=${encodeURIComponent(p.youtubeQuery)}`);
  };

  const handleFilterSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSelectedIdx(null);
    onSearch(searchComposer, searchMood, discoveryMode, era, searchPerformer, searchOccasion, searchInstrumentation);
  };

  const showFeedback = (msg: string) => {
    setCopyFeedback(msg);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  return (
    <div className="space-y-24 animate-in fade-in duration-1000">

      <section className="animate-in slide-in-from-top-4 duration-700">
        <div className="flex items-center justify-between mb-10 border-b border-stone-100 pb-4">
          <div className="flex items-center space-x-3">
            <Lightbulb className="w-5 h-5 text-[#9A84A1]" />
            <h3 className="text-xs font-black uppercase tracking-[0.3em] text-stone-900">CURATORIAL INSPIRATION</h3>
          </div>
          <button onClick={loadInspirations} className="text-[10px] font-black uppercase tracking-widest text-stone-300 hover:text-stone-900 flex items-center transition-colors">
            <RefreshCw className={`w-3 h-3 mr-2 ${loadingInspirations ? 'animate-spin' : ''}`} />
            Refresh Ideas
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {loadingInspirations ? (
            [1, 2, 3].map(i => <div key={i} className="h-32 bg-stone-50 border border-stone-100 rounded-3xl animate-pulse" />)
          ) : (
            inspirations.map((ins, i) => (
              <div 
                key={i}
                onClick={() => handleApplyInspiration(ins)}
                className="group p-8 bg-white border border-stone-100 rounded-3xl cursor-pointer hover:border-[#9A84A1] hover:shadow-xl transition-all duration-500 relative overflow-hidden"
              >
                <h4 className="text-sm font-black text-stone-900 mb-2 uppercase tracking-tight group-hover:text-[#9A84A1] transition-colors">{ins.theme}</h4>
                <p className="text-[11px] text-stone-400 font-medium leading-relaxed">{ins.reason}</p>
                <div className="mt-6 flex items-center text-[9px] font-black text-stone-900 uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-all translate-y-2 group-hover:translate-y-0">
                  Select Theme <Sparkles className="w-3 h-3 ml-2 text-[#9A84A1]" />
                </div>
              </div>
            ))
          )}
        </div>
      </section>

      <section className="bg-stone-900 p-12 md:p-16 rounded-[3rem] shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-16 opacity-10 pointer-events-none">
            <Compass className="w-64 h-64 text-[#9A84A1]" />
        </div>

        <form onSubmit={handleFilterSubmit} className="space-y-12 relative z-10">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            <div className="space-y-3">
              <label className="text-[10px] font-black uppercase text-white/40 tracking-[0.2em]">Occasion</label>
              <input type="text" value={searchOccasion} onChange={(e) => setSearchOccasion(e.target.value)} placeholder="e.g. Rainy Afternoon" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white focus:ring-2 focus:ring-[#9A84A1] font-bold placeholder:text-white/20" />
            </div>
            <div className="space-y-3">
              <label className="text-[10px] font-black uppercase text-white/40 tracking-[0.2em]">Instrument</label>
              <input type="text" value={searchInstrumentation} onChange={(e) => setSearchInstrumentation(e.target.value)} placeholder="e.g. Cello Solo" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white focus:ring-2 focus:ring-[#9A84A1] font-bold placeholder:text-white/20" />
            </div>
            <div className="space-y-3">
              <label className="text-[10px] font-black uppercase text-white/40 tracking-[0.2em]">Composer</label>
              <input type="text" value={searchComposer} onChange={(e) => setSearchComposer(e.target.value)} placeholder="Optional" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white focus:ring-2 focus:ring-[#9A84A1] font-bold placeholder:text-white/20" />
            </div>
            <div className="space-y-3">
              <label className="text-[10px] font-black uppercase text-white/40 tracking-[0.2em]">Soloist</label>
              <input type="text" value={searchPerformer} onChange={(e) => setSearchPerformer(e.target.value)} placeholder="Optional" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-2xl text-white focus:ring-2 focus:ring-[#9A84A1] font-bold placeholder:text-white/20" />
            </div>
          </div>

          <button type="submit" disabled={isSearching} className="w-full bg-[#9A84A1] text-white py-6 rounded-2xl font-black uppercase tracking-[0.3em] text-xs hover:bg-white hover:text-stone-900 transition-all transform active:scale-[0.98] shadow-2xl disabled:opacity-50 flex items-center justify-center space-x-4">
            {isSearching ? <RefreshCw className="w-6 h-6 animate-spin" /> : <Sparkles className="w-6 h-6" />}
            <span>{isSearching ? "Searching Archives..." : "Discover Masterpieces"}</span>
          </button>
        </form>
      </section>

      <section className="space-y-10">
        <div className="flex items-center space-x-4 mb-10 border-b border-stone-100 pb-4">
          <Music className="w-5 h-5 text-stone-900" />
          <h2 className="text-xs font-black uppercase tracking-[0.4em] text-stone-900">CURATED CANDIDATES</h2>
        </div>

        {isSearching ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {[1, 2, 3].map(i => <div key={i} className="bg-stone-50 h-48 rounded-[2.5rem] animate-pulse border border-stone-100" />)}
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {candidates.map((p, i) => (
