import React from 'react';
import { ClassicalPiece, SubscriptionTier } from '../types';
import { Calendar, ChevronRight, Lock, Music } from 'lucide-react';

interface HistoryListProps {
  items: ClassicalPiece[];
  tier: SubscriptionTier;
  onSelect: (piece: ClassicalPiece) => void;
  onUpgrade: () => void;
}

export const HistoryList: React.FC<HistoryListProps> = ({ items, tier, onSelect, onUpgrade }) => {
  const isPremium = tier === SubscriptionTier.PREMIUM;
  const visibleLimit = isPremium ? 100 : 3;

  if (items.length === 0) {
    return (
      <div className="text-center py-32 bg-stone-50 rounded-[3rem] border-2 border-dashed border-stone-100 max-w-4xl mx-auto">
        <Calendar className="w-12 h-12 text-stone-200 mx-auto mb-6" />
        <p className="text-stone-400 font-serif italic text-lg">The archives are currently silent.</p>
      </div>
    );
  }

  return (
    <div className="animate-in fade-in duration-700 max-w-4xl mx-auto">
      <div className="flex justify-between items-end mb-12 border-b border-stone-100 pb-6">
        <h3 className="text-4xl font-serif text-stone-900 font-bold">The Archives</h3>
        {!isPremium && (
          <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest mb-1">Showing 3 of {items.length} items</span>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {items.map((piece, index) => {
          const isLocked = index >= visibleLimit;

          return (
            <div 
              key={piece.id}
              onClick={() => isLocked ? onUpgrade() : onSelect(piece)}
              className={`group bg-white rounded-[2.5rem] overflow-hidden shadow-sm hover:shadow-xl border border-stone-50 transition-all cursor-pointer flex h-36 relative
                ${isLocked ? 'grayscale opacity-60' : ''}`}
            >
              {isLocked && (
                <div className="absolute inset-0 bg-white/40 backdrop-blur-[2px] z-10 flex items-center justify-center">
                  <div className="bg-stone-900 text-[#9A84A1] p-3 rounded-full shadow-xl">
                    <Lock className="w-4 h-4" />
                  </div>
                </div>
              )}

              <div className="w-32 flex-shrink-0 bg-stone-900 flex items-center justify-center text-[#9A84A1] overflow-hidden">
                <Music className="w-8 h-8 opacity-20" />
              </div>
              <div className="flex-grow p-8 flex flex-col justify-center min-w-0">
                <span className="text-[9px] text-[#9A84A1] font-black uppercase tracking-[0.2em] mb-2">{piece.date}</span>
                <h4 className="text-xl font-bold text-stone-900 serif truncate mb-1">{piece.title}</h4>
                <p className="text-stone-400 font-black uppercase tracking-widest text-[9px] truncate">{piece.composer}</p>
              </div>
              <div className="pr-6 flex items-center">
                <ChevronRight className="w-5 h-5 text-stone-100 group-hover:text-stone-900 transition" />
              </div>
            </div>
          );
        })}
      </div>

      {!isPremium && items.length > 3 && (
        <div className="mt-20 p-16 bg-stone-900 rounded-[3rem] text-center shadow-2xl">
          <h4 className="text-2xl font-serif text-white mb-4">Historical Full Access</h4>
          <p className="text-stone-400 mb-10 max-w-sm mx-auto text-sm leading-relaxed">아카이브의 모든 기록({items.length}곡)을 프리미엄 구독으로 자유롭게 탐색하세요.</p>
          <button onClick={onUpgrade} className="px-12 py-5 bg-[#9A84A1] text-white rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-white hover:text-stone-900 shadow-xl transition">Unlock Archive</button>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BoardPost, UserAccount } from '../types';
import { MessageSquare, Plus, ThumbsUp, User, Lock, Clock, Search, ChevronRight } from 'lucide-react';

interface CommunityBoardProps {
  currentUser: UserAccount | null;
  onLoginRequest: () => void;
}

export const CommunityBoard: React.FC<CommunityBoardProps> = ({ currentUser, onLoginRequest }) => {
  const [posts, setPosts] = useState<BoardPost[]>([]);
  const [showEditor, setShowEditor] = useState(false);
  const [newTitle, setNewTitle] = useState("");
  const [newContent, setNewContent] = useState("");

  useEffect(() => {
    const saved = localStorage.getItem('board_posts');
    if (saved) {
      setPosts(JSON.parse(saved));
    } else {
      const dummy: BoardPost[] = [
        { id: '1', title: '오늘의 바흐 무곡 정말 좋네요', author: '클래식광팬', content: '아침부터 듣는데 첼로 선율이 예술입니다.', timestamp: '2024-05-10 09:30', likes: 12 },
        { id: '2', title: '조성진 공연 티켓팅 팁 있나요?', author: '쇼팽매니아', content: '매번 광탈해서 이번엔 꼭 가고 싶습니다.', timestamp: '2024-05-09 15:45', likes: 8 },
      ];
      setPosts(dummy);
      localStorage.setItem('board_posts', JSON.stringify(dummy));
    }
  }, []);

  const handlePostSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) {
      onLoginRequest();
      return;
    }
    if (!newTitle.trim() || !newContent.trim()) return;

    const newPost: BoardPost = {
      id: Date.now().toString(),
      title: newTitle,
      author: currentUser.username,
      content: newContent,
      timestamp: new Date().toLocaleString(),
      likes: 0
    };

    const updated = [newPost, ...posts];
    setPosts(updated);
    localStorage.setItem('board_posts', JSON.stringify(updated));
    setNewTitle("");
    setNewContent("");
    setShowEditor(false);
  };

  const handleLike = (id: string) => {
    const updated = posts.map(p => p.id === id ? { ...p, likes: p.likes + 1 } : p);
    setPosts(updated);
    localStorage.setItem('board_posts', JSON.stringify(updated));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-4xl font-serif font-bold text-stone-900">Kyth Lounge</h2>
          <p className="text-stone-400 italic mt-1">음악 애호가들의 자유로운 소통 공간</p>
        </div>
        <button 
          onClick={() => currentUser ? setShowEditor(!showEditor) : onLoginRequest()}
          className="flex items-center justify-center space-x-2 px-6 py-3 bg-stone-900 text-white rounded-2xl font-bold hover:bg-[#9A84A1] transition shadow-lg"
        >
          {showEditor ? <span>Close</span> : <><Plus className="w-5 h-5" /> <span>Write Post</span></>}
        </button>
      </div>

      {!currentUser && (
        <div className="bg-[#F4F2F5] border border-stone-100 p-6 rounded-3xl flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <Lock className="w-6 h-6 text-[#9A84A1]" />
            <p className="text-stone-900 font-medium text-sm">글을 쓰려면 회원 로그인이 필요합니다.</p>
          </div>
          <button onClick={onLoginRequest} className="px-5 py-2 bg-stone-900 text-white rounded-xl text-xs font-bold hover:bg-[#9A84A1] transition">Login</button>
        </div>
      )}

      {showEditor && currentUser && (
        <form onSubmit={handlePostSubmit} className="bg-white p-8 rounded-[2.5rem] border border-stone-100 shadow-xl space-y-4 animate-in slide-in-from-top-4">
          <input 
            type="text" 
            placeholder="제목을 입력하세요"
            value={newTitle}
            onChange={(e) => setNewTitle(e.target.value)}
            className="w-full px-6 py-4 bg-stone-50 border border-stone-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-[#9A84A1] font-bold"
          />
          <textarea 
            placeholder="내용을 입력하세요..."
            value={newContent}
            onChange={(e) => setNewContent(e.target.value)}
            className="w-full h-40 px-6 py-4 bg-stone-50 border border-stone-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-[#9A84A1] resize-none"
          />
          <div className="flex justify-end">
            <button type="submit" className="px-10 py-3 bg-stone-900 text-white rounded-xl font-black hover:bg-[#9A84A1] transition">Submit Post</button>
          </div>
        </form>
      )}

      <div className="space-y-4">
        {posts.map((post) => (
          <div key={post.id} className="bg-white p-7 rounded-3xl shadow-sm border border-stone-50 hover:border-[#9A84A1]/30 transition group">
            <div className="flex justify-between items-start mb-4">
              <div>
                <h3 className="text-xl font-bold text-stone-900 mb-2 group-hover:text-[#9A84A1] transition-colors">{post.title}</h3>
                <div className="flex items-center space-x-4 text-xs text-stone-400">
                  <span className="flex items-center"><User className="w-3 h-3 mr-1" /> {post.author}</span>
                  <span className="flex items-center"><Clock className="w-3 h-3 mr-1" /> {post.timestamp}</span>
                </div>
              </div>
              <button 
                onClick={() => handleLike(post.id)}
                className="flex items-center space-x-1.5 px-3 py-1.5 rounded-full bg-stone-50 text-stone-600 hover:bg-[#9A84A1] hover:text-white transition"
              >
                <ThumbsUp className="w-3 h-3" />
                <span className="text-xs font-black">{post.likes}</span>
              </button>
            </div>
            <p className="text-stone-500 leading-relaxed text-sm line-clamp-3">{post.content}</p>
            <div className="mt-4 pt-4 border-t border-stone-50 flex justify-end">
                <button className="text-[10px] font-black uppercase text-[#9A84A1] flex items-center hover:text-stone-900 transition">
                  Read Full <ChevronRight className="w-3 h-3 ml-1" />
                </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Navbar } from './components/Navbar';
import { RecommendationCard } from './components/RecommendationCard';
import { HistoryList } from './components/HistoryList';
import { SubscriptionForm } from './components/SubscriptionForm';
import { PricingSection } from './components/PricingSection';
import { AdminPanel } from './components/AdminPanel';
import { CuratorWorkplace } from './components/CuratorWorkplace';
import { CommunityBoard } from './components/CommunityBoard';
import { PerformanceInfo } from './components/PerformanceInfo';
import { MyCollection } from './components/MyCollection';
import { AuthModal } from './components/AuthModal';
import { PaymentModal } from './components/PaymentModal';
import { generateCandidates } from './services/geminiService';
import { ClassicalPiece, ViewState, SubscriptionTier, UserAccount, Performance } from './types';
import { Loader2, User, Crown, Music } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.CURATE);
  const [tier, setTier] = useState<SubscriptionTier>(SubscriptionTier.FREE);
  const [todayPiece, setTodayPiece] = useState<ClassicalPiece | null>(null);
  const [candidates, setCandidates] = useState<ClassicalPiece[]>([]);
  const [history, setHistory] = useState<ClassicalPiece[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [isSearching, setIsSearching] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const [savedPieces, setSavedPieces] = useState<ClassicalPiece[]>([]);
  const [savedPerformances, setSavedPerformances] = useState<Performance[]>([]);

  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  const fetchCurationData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const today = new Date().toISOString().split('T')[0];
      const savedPiece = localStorage.getItem(`classic_daily_${today}`);

      if (savedPiece) {
        setTodayPiece(JSON.parse(savedPiece));
      } else {
        const results = await generateCandidates(today);
        setCandidates(results);
      }
    } catch (err) {
      console.error(err);
      setError("아카이브 데이터를 불러오지 못했습니다. 연결 상태를 확인해주세요.");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchCurationData();
    const savedHistory = localStorage.getItem('classic_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedUser = localStorage.getItem('classic_user');
    if (savedUser) {
      const user = JSON.parse(savedUser);
      setCurrentUser(user);
      const savedTier = localStorage.getItem(`tier_${user.email}`);
      if (savedTier) setTier(savedTier as SubscriptionTier);
    }

    const sp = localStorage.getItem('saved_pieces');
    if (sp) setSavedPieces(JSON.parse(sp));
    const spf = localStorage.getItem('saved_performances');
    if (spf) setSavedPerformances(JSON.parse(spf));
  }, [fetchCurationData]);

  const toggleSavePiece = (piece: ClassicalPiece) => {
    let updated;
    if (savedPieces.some(p => p.id === piece.id)) {
      updated = savedPieces.filter(p => p.id !== piece.id);
    } else {
      updated = [piece, ...savedPieces];
    }
    setSavedPieces(updated);
    localStorage.setItem('saved_pieces', JSON.stringify(updated));
  };

  const toggleSavePerformance = (perf: Performance) => {
    let updated;
    if (savedPerformances.some(p => p.id === perf.id)) {
      updated = savedPerformances.filter(p => p.id !== perf.id);
    } else {
      updated = [perf, ...savedPerformances];
    }
    setSavedPerformances(updated);
    localStorage.setItem('saved_performances', JSON.stringify(updated));
  };

  const handleCustomSearch = async (composer: string, mood: string, discoveryMode: any, era: string, performer: string, occasion: string, instrumentation: string) => {
    setIsSearching(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const results = await generateCandidates(today, { composer, mood, discoveryMode, era, performer, occasion, instrumentation });
      setCandidates(results);
    } catch (err) {
      console.error(err);
      alert("조건에 맞는 곡을 찾는 중 오류가 발생했습니다.");
    } finally {
      setIsSearching(false);
    }
  };

  const handleConfirmPiece = (piece: ClassicalPiece) => {
    const today = new Date().toISOString().split('T')[0];
    setTodayPiece(piece);
    localStorage.setItem(`classic_daily_${today}`, JSON.stringify(piece));

    const existingHistoryRaw = localStorage.getItem('classic_history');
    const existingHistory = existingHistoryRaw ? JSON.parse(existingHistoryRaw) : [];
    const updatedHistory = [piece, ...existingHistory.filter((p: any) => p.id !== piece.id)].slice(0, 10);
    localStorage.setItem('classic_history', JSON.stringify(updatedHistory));
    setHistory(updatedHistory);

    setCurrentView(ViewState.HOME);
  };

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    localStorage.setItem('classic_user', JSON.stringify(user));
    const savedTier = localStorage.getItem(`tier_${user.email}`);
    if (savedTier) setTier(savedTier as SubscriptionTier);
    else setTier(SubscriptionTier.FREE);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setTier(SubscriptionTier.FREE);
    localStorage.removeItem('classic_user');
  };

  const handleUpgradeSuccess = () => {
    if (!currentUser) return;
    setTier(SubscriptionTier.PREMIUM);
    localStorage.setItem(`tier_${currentUser.email}`, SubscriptionTier.PREMIUM);
  };

  const renderContent = () => {
    if (loading) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-8 text-center">
          <Loader2 className="w-10 h-10 text-stone-900 animate-spin" />
          <p className="text-[10px] font-bold uppercase tracking-[0.4em] text-stone-400">
            Scanning Archival Repositories
          </p>
        </div>
      );
    }

    if (error) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-6 space-y-6">
          <p className="text-stone-400 font-medium italic">{error}</p>
          <button onClick={fetchCurationData} className="px-10 py-4 bg-stone-900 text-white rounded-full font-bold uppercase tracking-widest text-xs shadow-xl">Retry Sync</button>
        </div>
      );
    }

    switch (currentView) {
      case ViewState.CURATE:
        return (
          <CuratorWorkplace 
            candidates={candidates} 
            onConfirm={handleConfirmPiece} 
            onSearch={handleCustomSearch}
            isSearching={isSearching}
          />
        );
      case ViewState.HOME:
        return todayPiece && (
          <RecommendationCard 
            piece={todayPiece} 
            tier={tier} 
            onUpgrade={() => setCurrentView(ViewState.PRICING)} 
            onSave={toggleSavePiece}
            isSaved={(id) => savedPieces.some(p => p.id === id)}
          />
        );
      case ViewState.PERFORMANCES:
        return (
          <PerformanceInfo 
            onSave={toggleSavePerformance}
            isSaved={(id) => savedPerformances.some(p => p.id === id)}
          />
        );
      case ViewState.MY_COLLECTION:
        return (
          <MyCollection 
            savedPieces={savedPieces}
            savedPerformances={savedPerformances}
            onRemovePiece={(id) => setSavedPieces(savedPieces.filter(p => p.id !== id))}
            onRemovePerformance={(id) => setSavedPerformances(savedPerformances.filter(p => p.id !== id))}
            onSelectPiece={(p) => { setTodayPiece(p); setCurrentView(ViewState.HOME); }}
          />
        );
      case ViewState.COMMUNITY:
        return <CommunityBoard currentUser={currentUser} onLoginRequest={() => setShowAuthModal(true)} />;
      case ViewState.HISTORY:
        return <HistoryList items={history} tier={tier} onSelect={(p) => { setTodayPiece(p); setCurrentView(ViewState.HOME); }} onUpgrade={() => setCurrentView(ViewState.PRICING)} />;
      case ViewState.PRICING:
        return <PricingSection currentTier={tier} onSelectPlan={() => currentUser ? setShowPaymentModal(true) : setShowAuthModal(true)} />;
      case ViewState.ADMIN:
        return <AdminPanel todayPiece={todayPiece} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-white text-stone-900">
      <Navbar activeView={currentView} setView={setCurrentView} tier={tier} />

      <main className="flex-grow container mx-auto px-6 py-16 max-w-6xl">
        <div className="mb-20 flex flex-col items-center">
          {currentUser && (
            <div className="mb-8 flex items-center space-x-4 bg-white px-5 py-2.5 rounded-full border border-stone-100 shadow-lg animate-in slide-in-from-top-4">
              <div className="w-6 h-6 bg-stone-900 rounded-full flex items-center justify-center text-[10px] text-[#9A84A1] font-bold">
                {tier === SubscriptionTier.PREMIUM ? <Crown className="w-3.5 h-3.5" /> : <User className="w-3.5 h-3.5" />}
              </div>
              <span className="text-[11px] font-bold uppercase tracking-widest">{currentUser.username}</span>
              <div className="w-px h-3 bg-stone-100 mx-2"></div>
              <button onClick={handleLogout} className="text-[10px] font-bold uppercase tracking-widest text-stone-300 hover:text-stone-900 transition">Logout</button>
            </div>
          )}

          <div className="inline-block px-5 py-1.5 bg-stone-900 text-[#9A84A1] text-[9px] font-bold uppercase tracking-[0.4em] rounded-full mb-6 shadow-md">
            Curatorial Excellence
          </div>
          <h1 className="text-3xl md:text-5xl font-bold text-stone-900 mb-4 tracking-tighter uppercase">Kyth Classical</h1>
          <p className="text-stone-400 text-sm md:text-base font-medium max-w-4xl text-center whitespace-nowrap">
            전 세계 아카이브에서 엄선된 클래식 명곡을 매일 한 곡씩 당신의 영혼에 전달합니다.
          </p>
        </div>

        {renderContent()}
      </main>

      <footer className="bg-stone-900 text-stone-500 py-20 px-6 text-center border-t border-stone-800">
        <p className="text-base italic mb-6 text-stone-300">"음악은 말로 표현할 수 없는 것을 표현한다." — 빅토르 위고</p>
        <p className="text-[10px] font-bold uppercase tracking-[0.5em] opacity-40">© 2025 Kyth Classical • Archive Collective</p>
      </footer>

      {showAuthModal && (
        <AuthModal 
          onClose={() => setShowAuthModal(false)} 
          onLogin={handleLogin}
        />
      )}

      {showPaymentModal && (
        <PaymentModal 
          onClose={() => setShowPaymentModal(false)} 
          onSuccess={handleUpgradeSuccess}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ClassicalPiece } from '../types';
import { getInspirations, CurationInspiration } from '../services/geminiService';
import { 
  Sparkles, Check, MessageCircle, Mail, Music, Search, 
  RefreshCw, Compass, Lightbulb, User, PenTool 
} from 'lucide-react';

interface CuratorWorkplaceProps {
  candidates: ClassicalPiece[];
  onConfirm: (piece: ClassicalPiece) => void;
  onSearch: (composer: string, mood: string, discoveryMode: string, era: string, performer: string, occasion: string, instrumentation: string) => void;
  isSearching: boolean;
}

export const CuratorWorkplace: React.FC<CuratorWorkplaceProps> = ({ candidates, onConfirm, onSearch, isSearching }) => {
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [editedText, setEditedText] = useState("");
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);

  const [searchComposer, setSearchComposer] = useState("");
  const [searchMood, setSearchMood] = useState("");
  const [searchPerformer, setSearchPerformer] = useState("");
  const [searchOccasion, setSearchOccasion] = useState("");
  const [searchInstrumentation, setSearchInstrumentation] = useState("");
  const [discoveryMode, setDiscoveryMode] = useState("balanced");
  const [era, setEra] = useState("");

  const [inspirations, setInspirations] = useState<CurationInspiration[]>([]);
  const [loadingInspirations, setLoadingInspirations] = useState(false);

  useEffect(() => {
    loadInspirations();
  }, []);

  const loadInspirations = async () => {
    setLoadingInspirations(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const items = await getInspirations(today);
      setInspirations(items);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingInspirations(false);
    }
  };

  const handleApplyInspiration = (ins: CurationInspiration) => {
    setSearchComposer(ins.filters.composer || "");
    setSearchPerformer(ins.filters.performer || "");
    setSearchMood(ins.filters.mood || "");
    setSearchOccasion(ins.filters.occasion || "");
    setSearchInstrumentation(ins.filters.instrumentation || "");
    setDiscoveryMode(ins.filters.discoveryMode || "balanced");
    setEra(ins.filters.era || "");

    onSearch(
      ins.filters.composer || "",
      ins.filters.mood || "",
      ins.filters.discoveryMode || "balanced",
      ins.filters.era || "",
      ins.filters.performer || "",
      ins.filters.occasion || "",
      ins.filters.instrumentation || ""
    );
  };

  const handleSelect = (i: number) => {
    setSelectedIdx(i);
    const p = candidates[i];
    setEditedText(`🎻 [Kyth Classical Daily Curation]\n\n✨ Masterpiece: ${p.composer} - ${p.title}\n🎹 Performed by: ${p.performer}\n\n[The Story]\n${p.description}\n\n[Maestro's Insight]\n${p.funFact}\n\n🎧 Listen: https://www.youtube.com/results?search_query=${encodeURIComponent(p.youtubeQuery)}`);
  };

  const handleFilterSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSelectedIdx(null);
    onSearch(searchComposer, searchMood, discoveryMode, era, searchPerformer, searchOccasion, searchInstrumentation);
  };

  const showFeedback = (msg: string) => {
    setCopyFeedback(msg);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  return (
    <div className="space-y-20 animate-in fade-in duration-1000">

      {/* Step 1: Inspiration - 제목 및 내용 크기 110% 확대 */}
      <section className="animate-in slide-in-from-top-4 duration-700">
        <div className="flex items-center justify-between mb-8 border-b border-stone-100 pb-4">
          <div className="flex items-center space-x-3">
            <Lightbulb className="w-6 h-6 text-[#9A84A1]" />
            <h3 className="text-base font-bold uppercase tracking-[0.25em] text-stone-900">CURATORIAL INSPIRATION</h3>
          </div>
          <button onClick={loadInspirations} className="text-[11px] font-bold uppercase tracking-widest text-stone-300 hover:text-stone-900 flex items-center transition-colors">
            <RefreshCw className={`w-3.5 h-3.5 mr-2 ${loadingInspirations ? 'animate-spin' : ''}`} />
            Refresh Ideas
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {loadingInspirations ? (
            [1, 2, 3].map(i => <div key={i} className="h-40 bg-stone-50 border border-stone-100 rounded-2xl animate-pulse" />)
          ) : (
            inspirations.map((ins, i) => (
              <div 
                key={i}
                onClick={() => handleApplyInspiration(ins)}
                className="group p-9 bg-white border border-stone-100 rounded-2xl cursor-pointer hover:border-[#9A84A1] hover:shadow-lg transition-all duration-300 relative overflow-hidden"
              >
                <h4 className="text-base font-bold text-stone-900 mb-3 uppercase tracking-tight group-hover:text-[#9A84A1] transition-colors">{ins.theme}</h4>
                <p className="text-[12px] text-stone-400 font-medium leading-relaxed">{ins.reason}</p>
                <div className="mt-6 flex items-center text-[10px] font-bold text-stone-900 uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-all translate-y-2 group-hover:translate-y-0">
                  Select Theme <Sparkles className="w-3.5 h-3.5 ml-2 text-[#9A84A1]" />
                </div>
              </div>
            ))
          )}
        </div>
      </section>

      {/* Step 2: Custom Discovery - 차콜색 배경, 무늬 제거, 한글화 */}
      <section className="bg-[#333333] p-10 md:p-14 rounded-[2.5rem] shadow-xl relative overflow-hidden no-pattern">
        <form onSubmit={handleFilterSubmit} className="space-y-10 relative z-10">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            <div className="space-y-3">
              <label className="text-[11px] font-bold uppercase text-white/40 tracking-[0.2em]">상황 / 테마</label>
              <input type="text" value={searchOccasion} onChange={(e) => setSearchOccasion(e.target.value)} placeholder="예: 비오는 오후" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-xl text-white focus:ring-1 focus:ring-[#9A84A1] font-medium placeholder:text-white/20 outline-none" />
            </div>
            <div className="space-y-3">
              <label className="text-[11px] font-bold uppercase text-white/40 tracking-[0.2em]">선호 악기</label>
              <input type="text" value={searchInstrumentation} onChange={(e) => setSearchInstrumentation(e.target.value)} placeholder="예: 첼로 솔로" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-xl text-white focus:ring-1 focus:ring-[#9A84A1] font-medium placeholder:text-white/20 outline-none" />
            </div>
            <div className="space-y-3">
              <label className="text-[11px] font-bold uppercase text-white/40 tracking-[0.2em]">작곡가</label>
              <input type="text" value={searchComposer} onChange={(e) => setSearchComposer(e.target.value)} placeholder="선택 사항" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-xl text-white focus:ring-1 focus:ring-[#9A84A1] font-medium placeholder:text-white/20 outline-none" />
            </div>
            <div className="space-y-3">
              <label className="text-[11px] font-bold uppercase text-white/40 tracking-[0.2em]">연주자</label>
              <input type="text" value={searchPerformer} onChange={(e) => setSearchPerformer(e.target.value)} placeholder="선택 사항" className="w-full px-6 py-4 bg-white/5 border border-white/10 rounded-xl text-white focus:ring-1 focus:ring-[#9A84A1] font-medium placeholder:text-white/20 outline-none" />
            </div>
          </div>

          <button type="submit" disabled={isSearching} className="w-full bg-[#9A84A1] text-white py-5 rounded-xl font-bold uppercase tracking-[0.25em] text-xs hover:bg-white hover:text-stone-900 transition-all transform active:scale-[0.98] shadow-lg disabled:opacity-50 flex items-center justify-center space-x-4">
            {isSearching ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
            <span>{isSearching ? "아카이브 탐색 중..." : "큐레이션 시작"}</span>
          </button>
        </form>
      </section>

      {/* Step 3: Candidate Selection - 제목 폰트 밸런스 조정 */}
      <section className="space-y-10">
        <div className="flex items-center space-x-4 mb-8 border-b border-stone-100 pb-4">
          <Music className="w-5 h-5 text-stone-900" />
          <h2 className="text-base font-bold uppercase tracking-[0.3em] text-stone-900">CURATED CANDIDATES</h2>
        </div>

        {isSearching ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {[1, 2, 3].map(i => <div key={i} className="bg-stone-50 h-56 rounded-2xl animate-pulse border border-stone-100" />)}
