import React, { useState, useEffect } from 'react';
import { ClassicalPiece } from '../types';
import { getInspirations, CurationInspiration } from '../services/geminiService';
import { 
  Sparkles, Check, MessageCircle, Mail, Music, Search, 
  RefreshCw, Lightbulb, PenTool 
} from 'lucide-react';

interface CuratorWorkplaceProps {
  candidates: ClassicalPiece[];
  onConfirm: (piece: ClassicalPiece) => void;
  onSearch: (composer: string, mood: string, discoveryMode: string, era: string, performer: string, occasion: string, instrumentation: string) => void;
  isSearching: boolean;
}

export const CuratorWorkplace: React.FC<CuratorWorkplaceProps> = ({ candidates, onConfirm, onSearch, isSearching }) => {
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [editedText, setEditedText] = useState("");
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);

  const [searchComposer, setSearchComposer] = useState("");
  const [searchMood, setSearchMood] = useState("");
  const [searchPerformer, setSearchPerformer] = useState("");
  const [searchOccasion, setSearchOccasion] = useState("");
  const [searchInstrumentation, setSearchInstrumentation] = useState("");
  const [discoveryMode, setDiscoveryMode] = useState("balanced");
  const [era, setEra] = useState("");

  const [inspirations, setInspirations] = useState<CurationInspiration[]>([]);
  const [loadingInspirations, setLoadingInspirations] = useState(false);

  useEffect(() => {
    loadInspirations();
  }, []);

  const loadInspirations = async () => {
    setLoadingInspirations(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const items = await getInspirations(today);
      setInspirations(items);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingInspirations(false);
    }
  };

  const handleApplyInspiration = (ins: CurationInspiration) => {
    setSearchComposer(ins.filters.composer || "");
    setSearchPerformer(ins.filters.performer || "");
    setSearchMood(ins.filters.mood || "");
    setSearchOccasion(ins.filters.occasion || "");
    setSearchInstrumentation(ins.filters.instrumentation || "");
    setDiscoveryMode(ins.filters.discoveryMode || "balanced");
    setEra(ins.filters.era || "");

    onSearch(
      ins.filters.composer || "",
      ins.filters.mood || "",
      ins.filters.discoveryMode || "balanced",
      ins.filters.era || "",
      ins.filters.performer || "",
      ins.filters.occasion || "",
      ins.filters.instrumentation || ""
    );
  };

  const handleSelect = (i: number) => {
    setSelectedIdx(i);
    const p = candidates[i];
    setEditedText(`🎻 [Kyth Classical Daily Curation]\n\n✨ Masterpiece: ${p.composer} - ${p.title}\n🎹 Performed by: ${p.performer}\n\n[The Story]\n${p.description}\n\n[Maestro's Insight]\n${p.funFact}\n\n🎧 Listen: https://www.youtube.com/results?search_query=${encodeURIComponent(p.youtubeQuery)}`);
  };

  const handleFilterSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSelectedIdx(null);
    onSearch(searchComposer, searchMood, discoveryMode, era, searchPerformer, searchOccasion, searchInstrumentation);
  };

  const showFeedback = (msg: string) => {
    setCopyFeedback(msg);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-1000">

      {/* Step 1: Inspiration */}
      <section className="animate-in slide-in-from-top-4 duration-700">
        <div className="flex items-center justify-between mb-8 border-b border-black/10 pb-4">
          <div className="flex items-center space-x-3">
            <Lightbulb className="w-7 h-7 text-stone-900" />
            <h3 className="text-xl font-bold uppercase tracking-[0.1em] text-stone-900">CURATORIAL INSPIRATION</h3>
          </div>
          <button onClick={loadInspirations} className="text-[10px] font-bold uppercase tracking-widest text-stone-900/40 hover:text-stone-900 flex items-center transition-colors">
            <RefreshCw className={`w-3.5 h-3.5 mr-2 ${loadingInspirations ? 'animate-spin' : ''}`} />
            새로고침
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {loadingInspirations ? (
            [1, 2, 3].map(i => <div key={i} className="h-44 bg-white/10 border border-white/10 rounded-2xl animate-pulse" />)
          ) : (
            inspirations.map((ins, i) => (
              <div 
                key={i}
                onClick={() => handleApplyInspiration(ins)}
                className="group p-8 bg-white/10 backdrop-blur-md border border-white/10 rounded-2xl cursor-pointer hover:bg-white/20 transition-all duration-300"
              >
                <h4 className="text-lg font-bold text-stone-900 mb-3 uppercase tracking-tight transition-colors">{ins.theme}</h4>
                <p className="text-[14px] text-stone-900/60 font-medium leading-relaxed">{ins.reason}</p>
              </div>
            ))
          )}
        </div>
      </section>

      {/* Step 2: Custom Discovery - 밝아진 차콜 배경, 한글화, 폰트 조절 */}
      <section className="bg-[#555555] p-10 md:p-14 rounded-[2.5rem] shadow-2xl relative overflow-hidden no-pattern border border-white/10">
        <form onSubmit={handleFilterSubmit} className="space-y-10 relative z-10">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            <div className="space-y-3">
              <label className="text-[14px] font-medium uppercase text-white/50 tracking-[0.1em]">상황 / 테마</label>
              <input type="text" value={searchOccasion} onChange={(e) => setSearchOccasion(e.target.value)} placeholder="예: 비오는 오후" className="w-full px-6 py-4 bg-white/10 border border-white/10 rounded-xl text-white focus:ring-1 focus:ring-white/40 font-normal placeholder:text-white/20 outline-none text-[16px]" />
            </div>
            <div className="space-y-3">
              <label className="text-[14px] font-medium uppercase text-white/50 tracking-[0.1em]">악기 / 구성</label>
              <input type="text" value={searchInstrumentation} onChange={(e) => setSearchInstrumentation(e.target.value)} placeholder="예: 첼로 솔로" className="w-full px-6 py-4 bg-white/10 border border-white/10 rounded-xl text-white focus:ring-1 focus:ring-white/40 font-normal placeholder:text-white/20 outline-none text-[16px]" />
            </div>
            <div className="space-y-3">
              <label className="text-[14px] font-medium uppercase text-white/50 tracking-[0.1em]">작곡가</label>
              <input type="text" value={searchComposer} onChange={(e) => setSearchComposer(e.target.value)} placeholder="선택사항" className="w-full px-6 py-4 bg-white/10 border border-white/10 rounded-xl text-white focus:ring-1 focus:ring-white/40 font-normal placeholder:text-white/20 outline-none text-[16px]" />
            </div>
            <div className="space-y-3">
              <label className="text-[14px] font-medium uppercase text-white/50 tracking-[0.1em]">연주자</label>
              <input type="text" value={searchPerformer} onChange={(e) => setSearchPerformer(e.target.value)} placeholder="선택사항" className="w-full px-6 py-4 bg-white/10 border border-white/10 rounded-xl text-white focus:ring-1 focus:ring-white/40 font-normal placeholder:text-white/20 outline-none text-[16px]" />
            </div>
          </div>

          <button type="submit" disabled={isSearching} className="w-full bg-stone-900 text-white py-5 rounded-xl font-bold uppercase tracking-[0.25em] text-xs hover:bg-white hover:text-stone-900 transition-all transform active:scale-[0.98] shadow-lg disabled:opacity-50 flex items-center justify-center space-x-4">
            {isSearching ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
            <span>{isSearching ? "탐색 중..." : "큐레이션 발견하기"}</span>
          </button>
        </form>
      </section>

      {/* Step 3: Candidate Selection - 헤더 블랙 및 텍스트 밸런스 */}
      <section className="space-y-10">
        <div className="flex items-center space-x-4 mb-8 border-b border-black/10 pb-4">
          <Music className="w-7 h-7 text-stone-900" />
          <h2 className="text-xl font-bold uppercase tracking-[0.1em] text-stone-900">CURATED CANDIDATES</h2>
        </div>

        {isSearching ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {[1, 2, 3].map(i => <div key={i} className="bg-white/10 h-60 rounded-[2.5rem] animate-pulse border border-white/10" />)}
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {candidates.map((p, i) => (
              <div 
                key={p.id}
                onClick={() => handleSelect(i)}
                className={`cursor-pointer group relative p-9 rounded-[2.5rem] border transition-all duration-300
                  ${selectedIdx === i ? 'bg-white border-stone-900 shadow-2xl scale-[1.02]' : 'bg-white/20 border-white/10 hover:bg-white/30 hover:border-white/30'}`}
              >
                <span className={`text-[11px] font-bold uppercase tracking-widest mb-2 block ${selectedIdx === i ? 'text-stone-400' : 'text-stone-900/60'}`}>{p.era}</span>
                <h4 className="text-lg font-bold text-stone-900 mb-2 leading-tight tracking-tight">{p.title}</h4>
                <p className="text-[13px] font-bold text-stone-900/80 uppercase tracking-widest">{p.composer}</p>
                <div className="mt-8 flex items-center text-[10px] font-bold uppercase tracking-widest text-stone-900/40 group-hover:text-stone-900 transition-colors">
                   {selectedIdx === i ? <Check className="w-4 h-4 mr-2" /> : <PenTool className="w-4 h-4 mr-2" />}
                   <span>{selectedIdx === i ? '선택됨' : '상세 확인'}</span>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Detailing Section - 밝아진 차콜 */}
      {selectedIdx !== null && (
        <section className="bg-[#555555] rounded-[2.5rem] shadow-2xl overflow-hidden animate-in slide-in-from-bottom-12 duration-700 no-pattern border border-white/10">
          <div className="p-10 md:p-16 grid grid-cols-1 lg:grid-cols-2 gap-16">
            <div className="space-y-5">
              <label className="text-[11px] font-bold uppercase tracking-[0.4em] text-white/40">Manuscript Editor</label>
              <textarea value={editedText} onChange={(e) => setEditedText(e.target.value)} className="w-full h-[350px] p-8 bg-white/5 border border-white/10 rounded-2xl text-white/80 leading-relaxed focus:outline-none focus:ring-1 focus:ring-white/40 transition-all text-base font-light shadow-inner resize-none" />
            </div>
            <div className="flex flex-col justify-center space-y-10">
              <div className="space-y-5">
                <h4 className="text-[11px] font-bold uppercase tracking-[0.4em] text-white/40">Distribution</h4>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <button onClick={() => { navigator.clipboard.writeText(editedText); showFeedback("복사됨"); }} className="flex flex-col items-center justify-center space-y-3 p-8 bg-white/5 hover:bg-white/10 text-white rounded-2xl border border-white/10 transition-all transform hover:-translate-y-0.5">
                    <MessageCircle className="w-6 h-6 text-[#9A84A1]" />
                    <span className="text-[10px] font-bold uppercase tracking-widest">Chat Copy</span>
                  </button>
                  <button onClick={() => { navigator.clipboard.writeText(editedText); showFeedback("복사됨"); }} className="flex flex-col items-center justify-center space-y-3 p-8 bg-white/5 hover:bg-white/10 text-white rounded-2xl border border-white/10 transition-all transform hover:-translate-y-0.5">
                    <Mail className="w-6 h-6 text-[#9A84A1]" />
                    <span className="text-[10px] font-bold uppercase tracking-widest">Email Copy</span>
                  </button>
                </div>
              </div>
              <button onClick={() => onConfirm(candidates[selectedIdx])} className="w-full py-6 bg-[#9A84A1] text-white font-bold uppercase tracking-[0.3em] text-xs rounded-xl hover:bg-white hover:text-stone-900 transition-all shadow-xl">
                Publish Masterpiece
              </button>
            </div>
          </div>
        </section>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Performance } from '../types';
import { getUpcomingPerformances } from '../services/geminiService';
import { Calendar, MapPin, User, ExternalLink, Loader2, Ticket, Search, Heart, Check, Music } from 'lucide-react';

interface PerformanceInfoProps {
  onSave: (p: Performance) => void;
  isSaved: (id: string) => boolean;
}

export const PerformanceInfo: React.FC<PerformanceInfoProps> = ({ onSave, isSaved }) => {
  const [performances, setPerformances] = useState<Performance[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [isSearching, setIsSearching] = useState(false);

  const fetchPerformances = async (query: string = "") => {
    if (query) setIsSearching(true);
    else setLoading(true);

    try {
      const today = new Date().toISOString().split('T')[0];
      const data = await getUpcomingPerformances(today, query);
      setPerformances(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
      setIsSearching(false);
    }
  };

  useEffect(() => {
    fetchPerformances();
  }, []);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    fetchPerformances(searchQuery);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-1000">
      <div className="text-center space-y-1">
        <h2 className="text-xl md:text-2xl font-bold text-white uppercase tracking-tight">Upcoming Concerts</h2>
        <p className="text-white/40 italic text-[9px] font-bold uppercase tracking-widest">Global Live Schedule</p>
      </div>

      <div className="bg-white/10 backdrop-blur-md p-6 rounded-[2rem] border border-white/10 shadow-xl">
        <form onSubmit={handleSearch} className="flex flex-col md:flex-row gap-4">
          <div className="relative flex-grow">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 w-4 h-4 text-white/40" />
            <input 
              type="text" 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="도시, 작곡가 또는 아티스트 검색..." 
              className="w-full pl-14 pr-6 py-4 bg-white/5 border border-white/5 rounded-xl text-white focus:outline-none focus:ring-1 focus:ring-white/40 text-sm placeholder:text-white/20" 
            />
          </div>
          <button 
            type="submit"
            disabled={isSearching}
            className="px-8 py-4 bg-stone-900 text-white rounded-xl font-bold uppercase tracking-widest text-[10px] hover:bg-white hover:text-stone-900 transition shadow-lg flex items-center justify-center space-x-3"
          >
            {isSearching ? <Loader2 className="w-4 h-4 animate-spin" /> : <Search className="w-4 h-4" />}
            <span>{isSearching ? "Searching..." : "공연 찾기"}</span>
          </button>
        </form>
      </div>

      {loading ? (
        <div className="flex flex-col items-center py-20 space-y-6">
          <Loader2 className="w-8 h-8 text-white animate-spin" />
        </div>
      ) : (
        <div className="space-y-4">
          {performances.map((p) => (
            <div key={p.id} className="bg-white rounded-[2rem] overflow-hidden shadow-sm border border-transparent flex flex-col md:flex-row group hover:shadow-2xl transition-all duration-500">
              <div className="md:w-40 h-40 md:h-auto bg-stone-900 flex items-center justify-center text-white relative overflow-hidden flex-shrink-0">
                <Music className="w-8 h-8 opacity-20" />
                <div className="absolute inset-0 flex items-center justify-center">
                   <div className="text-center">
                     <span className="block text-2xl font-bold text-white mb-1">{p.date.split('-')[2] || '??'}</span>
                     <span className="block text-[8px] font-bold uppercase tracking-widest opacity-40">Sept</span>
                   </div>
                </div>
              </div>
              <div className="p-8 flex flex-col justify-between flex-grow">
                <div className="space-y-3">
                  <h3 className="text-xl font-bold text-stone-900 tracking-tight">{p.title}</h3>
                  <div className="grid grid-cols-2 gap-4 text-[10px] font-bold text-stone-400 uppercase tracking-widest">
                    <span className="flex items-center"><MapPin className="w-3.5 h-3.5 mr-2" /> {p.venue}</span>
                    <span className="flex items-center"><User className="w-3.5 h-3.5 mr-2" /> {p.performer}</span>
                  </div>
                </div>
                <div className="mt-8 flex items-center justify-between border-t border-stone-50 pt-6">
                    <button 
                      onClick={() => onSave(p)}
                      className={`flex items-center space-x-2 px-3 py-1.5 rounded-lg text-[9px] font-bold uppercase tracking-widest transition
                        ${isSaved(p.id) ? 'text-stone-900' : 'text-stone-300 hover:text-stone-900'}`}
                    >
                      {isSaved(p.id) ? <Check className="w-3.5 h-3.5" /> : <Heart className="w-3.5 h-3.5" />}
                      <span>{isSaved(p.id) ? '저장됨' : '공연 저장'}</span>
                    </button>
                    <a 
                      href={p.link} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="flex items-center space-x-2 px-6 py-2 bg-stone-900 text-white rounded-lg font-bold uppercase tracking-widest text-[9px] hover:bg-[#9A84A1] transition shadow-md"
                    >
                      <span>상세보기</span>
                      <ExternalLink className="w-3 h-3" />
                    </a>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

