               <Ticket className="w-10 h-10 text-white/10 mx-auto mb-4" />
               <p className="text-white/40 font-medium text-sm">저장된 공연이 없습니다.</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 gap-4">
              {savedPerformances.map((p) => (
                <div key={p.id} className="bg-white p-8 rounded-[2rem] border border-transparent shadow-sm flex flex-col sm:flex-row items-center gap-8">
                   <div className="w-16 h-16 rounded-xl bg-stone-50 flex items-center justify-center text-stone-900 border border-stone-100">
                      <Calendar className="w-6 h-6 opacity-10" />
                   </div>
                   <div className="flex-grow text-center sm:text-left">
                     <span className="text-[9px] font-bold uppercase tracking-[0.2em] text-[#9A84A1] mb-1 block">{p.date}</span>
                     <h4 className="text-xl font-bold text-stone-900 mb-2">{p.title}</h4>
                     <div className="flex items-center justify-center sm:justify-start space-x-4 text-[9px] font-bold uppercase tracking-widest text-stone-400">
                        <span className="flex items-center"><MapPin className="w-3 h-3 mr-1.5 opacity-50" /> {p.venue}</span>
                        <span className="flex items-center"><ChevronRight className="w-3 h-3 mr-1.5 opacity-50" /> {p.performer}</span>
                     </div>
                   </div>
                   <div className="flex sm:flex-col gap-2 w-full sm:w-auto">
                     <a href={p.link} target="_blank" className="flex-grow sm:w-32 px-5 py-2.5 bg-stone-900 text-white rounded-lg font-bold uppercase tracking-widest text-[9px] text-center hover:bg-[#9A84A1] transition">Details</a>
                     <button 
                      onClick={() => onRemovePerformance(p.id)}
                      className="flex-grow sm:w-32 px-5 py-2.5 border border-stone-100 text-stone-400 rounded-lg font-bold uppercase tracking-widest text-[9px] hover:bg-red-50 hover:text-red-500 transition"
                     >
                       Remove
                     </button>
                   </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

