import React, { useState, useEffect, useCallback } from 'react';
import { Navbar } from './components/Navbar';
import { RecommendationCard } from './components/RecommendationCard';
import { HistoryList } from './components/HistoryList';
import { SubscriptionForm } from './components/SubscriptionForm';
import { PricingSection } from './components/PricingSection';
import { AdminPanel } from './components/AdminPanel';
import { CuratorWorkplace } from './components/CuratorWorkplace';
import { CommunityBoard } from './components/CommunityBoard';
import { PerformanceInfo } from './components/PerformanceInfo';
import { MyCollection } from './components/MyCollection';
import { AuthModal } from './components/AuthModal';
import { PaymentModal } from './components/PaymentModal';
import { generateCandidates } from './services/geminiService';
import { ClassicalPiece, ViewState, SubscriptionTier, UserAccount, Performance } from './types';
import { Loader2, User, Crown, Music } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.CURATE);
  const [tier, setTier] = useState<SubscriptionTier>(SubscriptionTier.FREE);
  const [todayPiece, setTodayPiece] = useState<ClassicalPiece | null>(null);
  const [candidates, setCandidates] = useState<ClassicalPiece[]>([]);
  const [history, setHistory] = useState<ClassicalPiece[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [isSearching, setIsSearching] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const [savedPieces, setSavedPieces] = useState<ClassicalPiece[]>([]);
  const [savedPerformances, setSavedPerformances] = useState<Performance[]>([]);

  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  const fetchCurationData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const today = new Date().toISOString().split('T')[0];
      const savedPiece = localStorage.getItem(`classic_daily_${today}`);

      if (savedPiece) {
        setTodayPiece(JSON.parse(savedPiece));
      } else {
        const results = await generateCandidates(today);
        setCandidates(results);
      }
    } catch (err) {
      console.error(err);
      setError("데이터를 불러오지 못했습니다.");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchCurationData();
    const savedHistory = localStorage.getItem('classic_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedUser = localStorage.getItem('classic_user');
    if (savedUser) {
      const user = JSON.parse(savedUser);
      setCurrentUser(user);
      const savedTier = localStorage.getItem(`tier_${user.email}`);
      if (savedTier) setTier(savedTier as SubscriptionTier);
    }

    const sp = localStorage.getItem('saved_pieces');
    if (sp) setSavedPieces(JSON.parse(sp));
    const spf = localStorage.getItem('saved_performances');
    if (spf) setSavedPerformances(JSON.parse(spf));
  }, [fetchCurationData]);

  const toggleSavePiece = (piece: ClassicalPiece) => {
    let updated;
    if (savedPieces.some(p => p.id === piece.id)) {
      updated = savedPieces.filter(p => p.id !== piece.id);
    } else {
      updated = [piece, ...savedPieces];
    }
    setSavedPieces(updated);
    localStorage.setItem('saved_pieces', JSON.stringify(updated));
  };

  const toggleSavePerformance = (perf: Performance) => {
    let updated;
    if (savedPerformances.some(p => p.id === perf.id)) {
      updated = savedPerformances.filter(p => p.id !== perf.id);
    } else {
      updated = [perf, ...savedPerformances];
    }
    setSavedPerformances(updated);
    localStorage.setItem('saved_performances', JSON.stringify(updated));
  };

  const handleCustomSearch = async (composer: string, mood: string, discoveryMode: any, era: string, performer: string, occasion: string, instrumentation: string) => {
    setIsSearching(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const results = await generateCandidates(today, { composer, mood, discoveryMode, era, performer, occasion, instrumentation });
      setCandidates(results);
    } catch (err) {
      console.error(err);
      alert("오류가 발생했습니다.");
    } finally {
      setIsSearching(false);
    }
  };

  const handleConfirmPiece = (piece: ClassicalPiece) => {
    const today = new Date().toISOString().split('T')[0];
    setTodayPiece(piece);
    localStorage.setItem(`classic_daily_${today}`, JSON.stringify(piece));

    const existingHistoryRaw = localStorage.getItem('classic_history');
    const existingHistory = existingHistoryRaw ? JSON.parse(existingHistoryRaw) : [];
    const updatedHistory = [piece, ...existingHistory.filter((p: any) => p.id !== piece.id)].slice(0, 10);
    localStorage.setItem('classic_history', JSON.stringify(updatedHistory));
    setHistory(updatedHistory);

    setCurrentView(ViewState.HOME);
  };

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    localStorage.setItem('classic_user', JSON.stringify(user));
    const savedTier = localStorage.getItem(`tier_${user.email}`);
    if (savedTier) setTier(savedTier as SubscriptionTier);
    else setTier(SubscriptionTier.FREE);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setTier(SubscriptionTier.FREE);
    localStorage.removeItem('classic_user');
  };

  const handleUpgradeSuccess = () => {
    if (!currentUser) return;
    setTier(SubscriptionTier.PREMIUM);
    localStorage.setItem(`tier_${currentUser.email}`, SubscriptionTier.PREMIUM);
  };

  const renderContent = () => {
    if (loading) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[40vh] space-y-6 text-center text-white">
          <Loader2 className="w-8 h-8 animate-spin" />
          <p className="text-[10px] font-bold uppercase tracking-[0.4em] opacity-60">Scanning Archives</p>
        </div>
      );
    }

    if (error) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[40vh] text-center p-6 space-y-6">
          <p className="text-white/60 text-sm">{error}</p>
          <button onClick={fetchCurationData} className="px-8 py-3 bg-white text-stone-900 rounded-full font-bold uppercase tracking-widest text-[10px] shadow-xl">Retry</button>
        </div>
      );
    }

    switch (currentView) {
      case ViewState.CURATE:
        return (
          <CuratorWorkplace 
            candidates={candidates} 
            onConfirm={handleConfirmPiece} 
            onSearch={handleCustomSearch}
            isSearching={isSearching}
          />
        );
      case ViewState.HOME:
        return todayPiece && (
          <RecommendationCard 
            piece={todayPiece} 
            tier={tier} 
            onUpgrade={() => setCurrentView(ViewState.PRICING)} 
            onSave={toggleSavePiece}
            isSaved={(id) => savedPieces.some(p => p.id === id)}
          />
        );
      case ViewState.PERFORMANCES:
        return (
          <PerformanceInfo 
            onSave={toggleSavePerformance}
            isSaved={(id) => savedPerformances.some(p => p.id === id)}
          />
        );
      case ViewState.MY_COLLECTION:
        return (
          <MyCollection 
            savedPieces={savedPieces}
            savedPerformances={savedPerformances}
            onRemovePiece={(id) => setSavedPieces(savedPieces.filter(p => p.id !== id))}
            onRemovePerformance={(id) => setSavedPerformances(savedPerformances.filter(p => p.id !== id))}
            onSelectPiece={(p) => { setTodayPiece(p); setCurrentView(ViewState.HOME); }}
          />
        );
      case ViewState.COMMUNITY:
        return <CommunityBoard currentUser={currentUser} onLoginRequest={() => setShowAuthModal(true)} />;
      case ViewState.HISTORY:
        return <HistoryList items={history} tier={tier} onSelect={(p) => { setTodayPiece(p); setCurrentView(ViewState.HOME); }} onUpgrade={() => setCurrentView(ViewState.PRICING)} />;
      case ViewState.PRICING:
        return <PricingSection currentTier={tier} onSelectPlan={() => currentUser ? setShowPaymentModal(true) : setShowAuthModal(true)} />;
      case ViewState.ADMIN:
        return <AdminPanel todayPiece={todayPiece} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#9A84A1] text-stone-900">
      <Navbar activeView={currentView} setView={setCurrentView} tier={tier} />

      <main className="flex-grow container mx-auto px-6 py-12 max-w-5xl">
        <div className="mb-14 flex flex-col items-center">
          {currentUser && (
            <div className="mb-6 flex items-center space-x-3 bg-white/10 backdrop-blur-md px-4 py-2 rounded-full border border-white/10 shadow-lg animate-in slide-in-from-top-4">
              <div className="w-5 h-5 bg-stone-900 rounded-full flex items-center justify-center text-[9px] text-white font-bold">
                {tier === SubscriptionTier.PREMIUM ? <Crown className="w-3 h-3" /> : <User className="w-3 h-3 text-white" />}
              </div>
              <span className="text-[10px] font-bold uppercase tracking-widest text-white">{currentUser.username}</span>
              <div className="w-px h-3 bg-white/20 mx-1"></div>
              <button onClick={handleLogout} className="text-[9px] font-bold uppercase tracking-widest text-white/40 hover:text-white transition">Logout</button>
            </div>
          )}

          <div className="inline-block px-4 py-1.5 bg-stone-900 text-white text-[8px] font-bold uppercase tracking-[0.4em] rounded-full mb-5 shadow-md">
            CURATORIAL EXCELLENCE
          </div>
          {/* 로고 크기 2배 확대, 블랙 색상, 자간 확대 */}
          <h1 className="text-4xl md:text-5xl font-logo font-black text-stone-900 mb-3 tracking-[0.05em]">Kyth Classical</h1>
          <p className="text-stone-900/60 text-[11px] md:text-[12px] font-semibold max-w-4xl text-center whitespace-nowrap tracking-wide">
            전 세계 아카이브에서 엄선된 클래식 명곡을 매일 한 곡씩 당신의 영혼에 전달합니다.
          </p>
        </div>

        {renderContent()}
      </main>

      <footer className="bg-stone-900/20 text-white/20 py-10 px-6 text-center">
        <p className="text-[10px] italic mb-3 text-white/40">"음악은 말로 표현할 수 없는 것을 표현한다." — 빅토르 위고</p>
        <p className="text-[7px] font-bold uppercase tracking-[0.5em]">© 2025 Kyth Classical • Archive Collective</p>
      </footer>

      {showAuthModal && (
        <AuthModal 
          onClose={() => setShowAuthModal(false)} 
          onLogin={handleLogin}
        />
      )}

      {showPaymentModal && (
        <PaymentModal 
          onClose={() => setShowPaymentModal(false)} 
          onSuccess={handleUpgradeSuccess}
        />
      )}
    </div>
  );
};

export default App;

