      </section>

      {/* Detailing Section */}
      {selectedIdx !== null && (
        <section className="bg-[#3D2C42] rounded-[2.5rem] shadow-2xl overflow-hidden animate-in slide-in-from-bottom-12 duration-700 no-pattern border border-white/10">
          <div className="p-10 md:p-16 grid grid-cols-1 lg:grid-cols-2 gap-16">
