          <div className="grid grid-cols-1 md:grid-cols-3 gap-12">
            {[1, 2, 3].map(i => <div key={i} className="bg-white h-80 rounded-[3.5rem] animate-pulse shadow-sm" />)}
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-12">
            {candidates.map((p, i) => (
              <div 
                key={p.id}
                onClick={() => handleSelect(i)}
                className={`cursor-pointer group relative p-12 rounded-[4rem] border transition-all duration-700
                  ${selectedIdx === i 
                    ? 'bg-white border-stone-900 shadow-premium scale-[1.05]' 
                    : 'bg-white/40 border-stone-100 hover:bg-white hover:shadow-xl hover:border-[#9A84A1]/20'}`}
              >
                <div className="absolute top-10 left-10 w-2 h-2 rounded-full bg-[#9A84A1] opacity-0 group-hover:opacity-100 transition-opacity"></div>
                <span className="text-[10px] font-black uppercase tracking-widest text-[#9A84A1] mb-4 block">{p.era}</span>
                <h4 className="text-2xl font-logo font-black text-stone-900 mb-4 leading-none tracking-tight">{p.title}</h4>
                <p className="text-[13px] font-bold text-stone-400 uppercase tracking-widest mb-10">{p.composer}</p>
                <div className={`flex items-center text-[10px] font-black uppercase tracking-widest transition-colors
                   ${selectedIdx === i ? 'text-stone-900' : 'text-stone-200 group-hover:text-stone-900'}`}>
                   {selectedIdx === i ? <Check className="w-4 h-4 mr-3" /> : <PenTool className="w-4 h-4 mr-3" />}
                   <span>{selectedIdx === i ? 'In Review' : 'Edit Manuscript'}</span>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Detailing Section - 에디토리얼 시뮬레이터 */}
      {selectedIdx !== null && (
        <section className="bg-white rounded-[4rem] shadow-premium overflow-hidden animate-in slide-in-from-bottom-20 duration-1000 border border-stone-100">
          <div className="p-12 md:p-24 grid grid-cols-1 lg:grid-cols-2 gap-24">
            <div className="space-y-8">
              <div className="flex items-center justify-between">
                 <label className="text-[10px] font-black uppercase tracking-[0.5em] text-[#9A84A1]">Manuscript Editor</label>
                 <span className="text-[9px] font-bold text-stone-300 uppercase tracking-widest">Live Auto-Save Active</span>
              </div>
              <textarea 
                value={editedText} 
                onChange={(e) => setEditedText(e.target.value)} 
                className="w-full h-[500px] p-12 bg-stone-50 border border-stone-100 rounded-[3rem] text-stone-900 leading-[1.8] focus:outline-none focus:ring-1 focus:ring-[#9A84A1] transition-all text-lg font-light shadow-inner-soft resize-none" 
              />
            </div>

            <div className="flex flex-col justify-center space-y-16">
              <div className="space-y-8">
                <h4 className="text-[10px] font-black uppercase tracking-[0.5em] text-[#9A84A1]">Publishing Options</h4>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                  <button onClick={() => { navigator.clipboard.writeText(editedText); showFeedback("Copied to Clipboard"); }} className="flex flex-col items-center justify-center space-y-6 p-12 bg-stone-50 hover:bg-[#9A84A1]/5 text-stone-900 rounded-[3rem] border border-stone-100 transition-all transform hover:-translate-y-2 group shadow-sm">
                    <div className="w-14 h-14 rounded-full bg-white flex items-center justify-center shadow-md group-hover:bg-white group-hover:shadow-xl transition-all">
                      <MessageCircle className="w-6 h-6 text-[#9A84A1]" />
                    </div>
                    <span className="text-[11px] font-black uppercase tracking-widest">Chat Broadcast</span>
                  </button>
                  <button onClick={() => { navigator.clipboard.writeText(editedText); showFeedback("Copied to Clipboard"); }} className="flex flex-col items-center justify-center space-y-6 p-12 bg-stone-50 hover:bg-[#9A84A1]/5 text-stone-900 rounded-[3rem] border border-stone-100 transition-all transform hover:-translate-y-2 group shadow-sm">
                    <div className="w-14 h-14 rounded-full bg-white flex items-center justify-center shadow-md group-hover:bg-white group-hover:shadow-xl transition-all">
                      <Mail className="w-6 h-6 text-[#9A84A1]" />
                    </div>
                    <span className="text-[11px] font-black uppercase tracking-widest">Newsletter Post</span>
                  </button>
                </div>
              </div>

              <div className="space-y-6 pt-10 border-t border-stone-50">
                 <button 
                   onClick={() => onConfirm(candidates[selectedIdx])} 
                   className="w-full py-8 bg-stone-900 text-white font-black uppercase tracking-[0.5em] text-[11px] rounded-2xl hover:bg-[#9A84A1] transition-all shadow-2xl active:scale-95"
                 >
                   Establish Official Daily Curation
                 </button>
                 <p className="text-center text-[9px] font-bold text-stone-300 uppercase tracking-widest">Once published, the piece will be available in the public archive.</p>
              </div>
            </div>
          </div>

          {copyFeedback && (
            <div className="fixed bottom-10 left-1/2 -translate-x-1/2 glass px-10 py-4 rounded-full text-xs font-bold text-[#9A84A1] shadow-2xl animate-in fade-in slide-in-from-bottom-4">
              {copyFeedback}
            </div>
          )}
        </section>
      )}
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Navbar } from './components/Navbar';
import { RecommendationCard } from './components/RecommendationCard';
import { HistoryList } from './components/HistoryList';
import { SubscriptionForm } from './components/SubscriptionForm';
import { PricingSection } from './components/PricingSection';
import { AdminPanel } from './components/AdminPanel';
import { CuratorWorkplace } from './components/CuratorWorkplace';
import { CommunityBoard } from './components/CommunityBoard';
import { PerformanceInfo } from './components/PerformanceInfo';
import { MyCollection } from './components/MyCollection';
import { AuthModal } from './components/AuthModal';
import { PaymentModal } from './components/PaymentModal';
import { generateCandidates } from './services/geminiService';
import { ClassicalPiece, ViewState, SubscriptionTier, UserAccount, Performance } from './types';
import { Loader2, User, Crown, Music, Asterisk } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.CURATE);
  const [tier, setTier] = useState<SubscriptionTier>(SubscriptionTier.FREE);
  const [todayPiece, setTodayPiece] = useState<ClassicalPiece | null>(null);
  const [candidates, setCandidates] = useState<ClassicalPiece[]>([]);
  const [history, setHistory] = useState<ClassicalPiece[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [isSearching, setIsSearching] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const [savedPieces, setSavedPieces] = useState<ClassicalPiece[]>([]);
  const [savedPerformances, setSavedPerformances] = useState<Performance[]>([]);

  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  const fetchCurationData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const today = new Date().toISOString().split('T')[0];
      const savedPiece = localStorage.getItem(`classic_daily_${today}`);

      if (savedPiece) {
        setTodayPiece(JSON.parse(savedPiece));
      } else {
        const results = await generateCandidates(today);
        setCandidates(results);
      }
    } catch (err) {
      console.error(err);
      setError("데이터를 불러오지 못했습니다.");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchCurationData();
    const savedHistory = localStorage.getItem('classic_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedUser = localStorage.getItem('classic_user');
    if (savedUser) {
      const user = JSON.parse(savedUser);
      setCurrentUser(user);
      const savedTier = localStorage.getItem(`tier_${user.email}`);
      if (savedTier) setTier(savedTier as SubscriptionTier);
    }

    const sp = localStorage.getItem('saved_pieces');
    if (sp) setSavedPieces(JSON.parse(sp));
    const spf = localStorage.getItem('saved_performances');
    if (spf) setSavedPerformances(JSON.parse(spf));
  }, [fetchCurationData]);

  const toggleSavePiece = (piece: ClassicalPiece) => {
    let updated;
    if (savedPieces.some(p => p.id === piece.id)) {
      updated = savedPieces.filter(p => p.id !== piece.id);
    } else {
      updated = [piece, ...savedPieces];
    }
    setSavedPieces(updated);
    localStorage.setItem('saved_pieces', JSON.stringify(updated));
  };

  const toggleSavePerformance = (perf: Performance) => {
    let updated;
    if (savedPerformances.some(p => p.id === perf.id)) {
      updated = savedPerformances.filter(p => p.id !== perf.id);
    } else {
      updated = [perf, ...savedPerformances];
    }
    setSavedPerformances(updated);
    localStorage.setItem('saved_performances', JSON.stringify(updated));
  };

  const handleCustomSearch = async (composer: string, mood: string, discoveryMode: any, era: string, performer: string, occasion: string, instrumentation: string) => {
    setIsSearching(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const results = await generateCandidates(today, { composer, mood, discoveryMode, era, performer, occasion, instrumentation });
      setCandidates(results);
    } catch (err) {
      console.error(err);
      alert("오류가 발생했습니다.");
    } finally {
      setIsSearching(false);
    }
  };

  const handleConfirmPiece = (piece: ClassicalPiece) => {
    const today = new Date().toISOString().split('T')[0];

    // 1. 오늘의 곡 상태 즉시 업데이트
    setTodayPiece(piece);
    localStorage.setItem(`classic_daily_${today}`, JSON.stringify(piece));

    // 2. 히스토리 관리
    const existingHistoryRaw = localStorage.getItem('classic_history');
    const existingHistory = existingHistoryRaw ? JSON.parse(existingHistoryRaw) : [];
    const updatedHistory = [piece, ...existingHistory.filter((p: any) => p.id !== piece.id)].slice(0, 10);
    localStorage.setItem('classic_history', JSON.stringify(updatedHistory));
    setHistory(updatedHistory);

    // 3. 메인 화면으로 전환
    setCurrentView(ViewState.HOME);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    localStorage.setItem('classic_user', JSON.stringify(user));
    const savedTier = localStorage.getItem(`tier_${user.email}`);
    if (savedTier) setTier(savedTier as SubscriptionTier);
    else setTier(SubscriptionTier.FREE);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setTier(SubscriptionTier.FREE);
    localStorage.removeItem('classic_user');
  };

  const handleUpgradeSuccess = () => {
    if (!currentUser) return;
    setTier(SubscriptionTier.PREMIUM);
    localStorage.setItem(`tier_${currentUser.email}`, SubscriptionTier.PREMIUM);
  };

  const renderContent = () => {
    if (loading) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[50vh] space-y-8 text-center">
          <div className="relative">
            <Loader2 className="w-12 h-12 animate-spin text-[#9A84A1]" />
            <div className="absolute inset-0 flex items-center justify-center">
              <Asterisk className="w-4 h-4 text-stone-300" />
            </div>
          </div>
          <p className="text-[11px] font-bold uppercase tracking-[0.5em] text-stone-400 animate-pulse">Syncing Archive Vol. 25</p>
        </div>
      );
    }

    if (error) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[50vh] text-center p-6 space-y-8">
          <p className="text-stone-400 font-medium text-lg italic serif">"음악이 잠시 멈췄습니다. 다시 연주할 준비가 필요합니다."</p>
          <button onClick={fetchCurationData} className="px-12 py-4 bg-stone-900 text-white font-bold uppercase tracking-widest text-[10px] hover:bg-[#9A84A1] transition-all">Re-Tuning</button>
        </div>
      );
    }

    switch (currentView) {
      case ViewState.CURATE:
        return (
          <CuratorWorkplace 
            candidates={candidates} 
            onConfirm={handleConfirmPiece} 
            onSearch={handleCustomSearch}
            isSearching={isSearching}
          />
        );
      case ViewState.HOME:
        return todayPiece && (
          <RecommendationCard 
            piece={todayPiece} 
            tier={tier} 
            onUpgrade={() => setCurrentView(ViewState.PRICING)} 
            onSave={toggleSavePiece}
            isSaved={(id) => savedPieces.some(p => p.id === id)}
          />
        );
      case ViewState.PERFORMANCES:
        return (
          <PerformanceInfo 
            onSave={toggleSavePerformance}
            isSaved={(id) => savedPerformances.some(p => p.id === id)}
          />
        );
      case ViewState.MY_COLLECTION:
        return (
          <MyCollection 
            savedPieces={savedPieces}
            savedPerformances={savedPerformances}
            onRemovePiece={(id) => setSavedPieces(savedPieces.filter(p => p.id !== id))}
            onRemovePerformance={(id) => setSavedPerformances(savedPerformances.filter(p => p.id !== id))}
            onSelectPiece={(p) => { setTodayPiece(p); setCurrentView(ViewState.HOME); }}
          />
        );
      case ViewState.COMMUNITY:
        return <CommunityBoard currentUser={currentUser} onLoginRequest={() => setShowAuthModal(true)} />;
      case ViewState.HISTORY:
        return <HistoryList items={history} tier={tier} onSelect={(p) => { setTodayPiece(p); setCurrentView(ViewState.HOME); }} onUpgrade={() => setCurrentView(ViewState.PRICING)} />;
      case ViewState.PRICING:
        return <PricingSection currentTier={tier} onSelectPlan={() => currentUser ? setShowPaymentModal(true) : setShowAuthModal(true)} />;
      case ViewState.ADMIN:
        return <AdminPanel todayPiece={todayPiece} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#F8F5FA] text-[#1A1A1A]">
      <Navbar activeView={currentView} setView={setCurrentView} tier={tier} />

      <main className="flex-grow container mx-auto px-6 py-24 max-w-6xl">
        {/* Editorial Header Section */}
        <div className="mb-24 flex flex-col items-center text-center">
          {currentUser && (
            <div className="mb-8 flex items-center space-x-4 glass px-5 py-2 border border-stone-200 shadow-sm transition-all hover:shadow-md">
              <div className="w-6 h-6 bg-stone-900 flex items-center justify-center text-[10px] text-white">
                {tier === SubscriptionTier.PREMIUM ? <Crown className="w-3 h-3 text-[#9A84A1]" /> : <User className="w-3.5 h-3.5" />}
              </div>
              <span className="text-[11px] font-bold uppercase tracking-widest text-stone-600">{currentUser.username}</span>
              <div className="w-px h-3 bg-stone-200"></div>
              <button onClick={handleLogout} className="text-[10px] font-bold uppercase tracking-widest text-stone-300 hover:text-stone-900 transition">Exit</button>
            </div>
          )}

          <div className="flex items-center space-x-4 mb-6">
            <div className="h-px w-8 bg-stone-200"></div>
            <div className="text-[9px] font-bold uppercase tracking-[0.6em] text-stone-400">Archive Collective</div>
            <div className="h-px w-8 bg-stone-200"></div>
          </div>

          <h1 className="text-7xl md:text-9xl font-logo font-black text-black mb-6 tracking-[-0.02em] leading-tight">
            Kyth <span className="serif-italic font-normal italic text-[#9A84A1] block md:inline md:ml-4">Classical</span>
          </h1>

          <div className="max-w-2xl mx-auto space-y-4">
            <p className="text-stone-500 text-sm md:text-base font-medium tracking-wide leading-relaxed">
              정밀하게 큐레이션된 고전의 정수, 매일 한 곡의 마스터피스가 당신의 영혼을 깨웁니다.
            </p>
            <div className="flex justify-center items-center space-x-4 text-[9px] font-black uppercase tracking-[0.3em] text-[#9A84A1]">
               <span>Curated</span>
               <Asterisk className="w-3 h-3" />
               <span>Timeless</span>
               <Asterisk className="w-3 h-3" />
               <span>Exclusive</span>
            </div>
          </div>
        </div>

        {renderContent()}
      </main>

      <footer className="bg-white border-t border-stone-100 py-24 px-6 text-center">
        <div className="max-w-xs mx-auto mb-10">
          <div className="text-2xl font-logo font-bold mb-2">Kyth</div>
          <p className="text-[10px] text-stone-400 leading-relaxed uppercase tracking-widest">A legacy of sound and emotion curated for the modern connoisseur.</p>
        </div>
        <p className="text-[10px] italic mb-6 text-stone-300 serif-italic">"음악은 말로 표현할 수 없는 것을 표현한다." — Victor Hugo</p>
        <div className="flex justify-center space-x-12 text-[8px] font-bold uppercase tracking-[0.4em] text-stone-400">
          <a href="#" className="hover:text-[#9A84A1] transition">Terms</a>
          <a href="#" className="hover:text-[#9A84A1] transition">Privacy</a>
          <a href="#" className="hover:text-[#9A84A1] transition">Contact</a>
        </div>
        <p className="text-[8px] font-bold uppercase tracking-[0.5em] text-stone-200 mt-12">© 2025 KYTH CLASSICAL ARCHIVE</p>
      </footer>

      {showAuthModal && (
        <AuthModal 
          onClose={() => setShowAuthModal(false)} 
          onLogin={handleLogin}
        />
      )}

      {showPaymentModal && (
        <PaymentModal 
          onClose={() => setShowPaymentModal(false)} 
          onSuccess={handleUpgradeSuccess}
        />
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ClassicalPiece } from '../types';
import { getInspirations, CurationInspiration } from '../services/geminiService';
import { 
  Sparkles, Check, MessageCircle, Mail, Music, Search, 
  RefreshCw, Lightbulb, PenTool, ArrowUpRight, Asterisk, Loader2
} from 'lucide-react';

interface CuratorWorkplaceProps {
  candidates: ClassicalPiece[];
  onConfirm: (piece: ClassicalPiece) => void;
  onSearch: (composer: string, mood: string, discoveryMode: string, era: string, performer: string, occasion: string, instrumentation: string) => void;
  isSearching: boolean;
}

export const CuratorWorkplace: React.FC<CuratorWorkplaceProps> = ({ candidates, onConfirm, onSearch, isSearching }) => {
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [editedText, setEditedText] = useState("");
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);

  const [searchComposer, setSearchComposer] = useState("");
  const [searchMood, setSearchMood] = useState("");
  const [searchPerformer, setSearchPerformer] = useState("");
  const [searchOccasion, setSearchOccasion] = useState("");
  const [searchInstrumentation, setSearchInstrumentation] = useState("");
  const [discoveryMode, setDiscoveryMode] = useState("balanced");
  const [era, setEra] = useState("");

  const [inspirations, setInspirations] = useState<CurationInspiration[]>([]);
  const [loadingInspirations, setLoadingInspirations] = useState(false);

  useEffect(() => {
    loadInspirations();
  }, []);

  const loadInspirations = async () => {
    setLoadingInspirations(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const items = await getInspirations(today);
      setInspirations(items);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingInspirations(false);
    }
  };

  const handleApplyInspiration = (ins: CurationInspiration) => {
    setSearchComposer(ins.filters.composer || "");
    setSearchPerformer(ins.filters.performer || "");
    setSearchMood(ins.filters.mood || "");
    setSearchOccasion(ins.filters.occasion || "");
    setSearchInstrumentation(ins.filters.instrumentation || "");
    setDiscoveryMode(ins.filters.discoveryMode || "balanced");
    setEra(ins.filters.era || "");

    onSearch(
      ins.filters.composer || "",
      ins.filters.mood || "",
      ins.filters.discoveryMode || "balanced",
      ins.filters.era || "",
      ins.filters.performer || "",
      ins.filters.occasion || "",
      ins.filters.instrumentation || ""
    );
  };

  const handleSelect = (i: number) => {
    setSelectedIdx(i);
    const p = candidates[i];
    setEditedText(`🎻 [Kyth Classical Daily Curation]\n\n✨ Masterpiece: ${p.composer} - ${p.title}\n🎹 Performed by: ${p.performer}\n\n[The Story]\n${p.description}\n\n[Maestro's Insight]\n${p.funFact}\n\n🎧 Listen: https://www.youtube.com/results?search_query=${encodeURIComponent(p.youtubeQuery)}`);
  };

  const handleFilterSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSelectedIdx(null);
    onSearch(searchComposer, searchMood, discoveryMode, era, searchPerformer, searchOccasion, searchInstrumentation);
  };

  const showFeedback = (msg: string) => {
    setCopyFeedback(msg);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  return (
    <div className="space-y-24 animate-in fade-in duration-1000 max-w-6xl mx-auto">

      {/* 1. Discovery Engine (Core Function) - 최상단으로 이동 & 화이트 테마 */}
      <section className="bg-white p-12 md:p-16 border border-stone-200 shadow-premium relative group">
        <div className="flex items-center space-x-3 mb-10">
           <div className="w-1 h-1 bg-[#9A84A1] animate-pulse"></div>
           <span className="text-[10px] font-black uppercase tracking-[0.5em] text-stone-400">Master Curation Engine</span>
        </div>

        <form onSubmit={handleFilterSubmit} className="space-y-12 relative z-10">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12">
            {[
              { label: 'Occasion / Scene', value: searchOccasion, setter: setSearchOccasion, placeholder: '예: 비오는 오후' },
              { label: 'Instrumentation', value: searchInstrumentation, setter: setSearchInstrumentation, placeholder: '예: 첼로 솔로' },
              { label: 'Composer', value: searchComposer, setter: setSearchComposer, placeholder: 'Specific (Optional)' },
              { label: 'Virtuoso', value: searchPerformer, setter: setSearchPerformer, placeholder: 'Specific (Optional)' },
            ].map((f, idx) => (
              <div key={idx} className="space-y-4">
                <label className="text-[10px] font-black uppercase text-stone-400 tracking-[0.2em]">{f.label}</label>
                <div className="relative group">
                  <input 
                    type="text" 
                    value={f.value} 
                    onChange={(e) => f.setter(e.target.value)} 
                    placeholder={f.placeholder} 
                    className="w-full px-0 py-4 bg-transparent border-b border-stone-200 text-stone-900 focus:border-[#9A84A1] transition-all outline-none font-light text-lg placeholder:text-stone-200" 
                  />
                  <div className="absolute bottom-0 left-0 w-0 h-[1.5px] bg-[#9A84A1] group-focus-within:w-full transition-all duration-700"></div>
                </div>
              </div>
            ))}
          </div>

          <button 
            type="submit" 
            disabled={isSearching} 
            className="w-full bg-stone-900 text-white py-7 font-black uppercase tracking-[0.5em] text-xs hover:bg-[#9A84A1] transition-all transform active:scale-[0.98] shadow-2xl disabled:opacity-50 flex items-center justify-center space-x-6 group"
          >
            {isSearching ? <Loader2 className="w-6 h-6 animate-spin" /> : <Sparkles className="w-6 h-6 group-hover:rotate-12 transition-transform" />}
            <span>{isSearching ? "Synthesizing Masterpieces..." : "Analyze & Discover"}</span>
          </button>
        </form>
