          </div>

          {copyFeedback && (
            <div className="fixed bottom-10 left-1/2 -translate-x-1/2 glass px-10 py-4 font-bold text-[#9A84A1] shadow-2xl animate-in fade-in slide-in-from-bottom-4 z-50">
