  const isPremium = tier === SubscriptionTier.PREMIUM;
  const visibleLimit = isPremium ? 100 : 3;

  if (items.length === 0) {
    return (
      <div className="text-center py-40 bg-[#F8F5FA] border border-stone-100 shadow-sm max-w-4xl mx-auto">
        <Calendar className="w-12 h-12 text-stone-200 mx-auto mb-8" />
        <p className="text-stone-400 font-logo italic text-2xl">아카이브가 아직 비어 있습니다.</p>
      </div>
    );
  }

  return (
    <div className="animate-in fade-in duration-700 max-w-4xl mx-auto pb-20">
      <div className="flex justify-between items-end mb-16 border-b border-stone-900 pb-8">
         <div className="space-y-2">
           <span className="text-[10px] font-black uppercase tracking-[0.4em] text-[#9A84A1]">역사적 기록</span>
           <h3 className="text-5xl font-logo text-stone-900 font-black">Archive Logs</h3>
         </div>
        {!isPremium && (
          <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest mb-1">최근 3곡만 공개 중</span>
        )}
      </div>

      <div className="grid grid-cols-1 gap-6">
        {items.map((piece, index) => {
          const isLocked = index >= visibleLimit;

          return (
            <div 
              key={piece.id}
              onClick={() => isLocked ? onUpgrade() : onSelect(piece)}
              className={`group bg-[#F8F5FA] border border-stone-50 shadow-sm hover:shadow-premium transition-all cursor-pointer flex h-40 relative
                ${isLocked ? 'grayscale opacity-40' : ''}`}
            >
              {isLocked && (
                <div className="absolute inset-0 bg-white/60 backdrop-blur-[1px] z-10 flex items-center justify-center">
                  <div className="bg-stone-900 text-[#9A84A1] p-4 shadow-2xl">
                    <Lock className="w-5 h-5" />
                  </div>
                </div>
              )}

              <div className="w-40 flex-shrink-0 bg-stone-900 flex items-center justify-center text-[#9A84A1] overflow-hidden">
                <Music className="w-10 h-10 opacity-10" />
              </div>
              <div className="flex-grow p-10 flex flex-col justify-center min-w-0">
