      </div>

      {!isPremium && items.length > 3 && (
        <div className="mt-24 p-20 bg-stone-900 text-center shadow-premium">
          <h4 className="text-3xl font-logo font-black text-white mb-6 uppercase tracking-tight">전체 접근이 제한됨</h4>
          <p className="text-stone-400 mb-12 max-w-sm mx-auto text-sm leading-relaxed font-medium">모든 아카이브 기록과 고해상도 해설을 프리미엄 구독으로 탐험하세요.</p>
          <button onClick={onUpgrade} className="px-14 py-6 bg-[#9A84A1] text-white font-black text-xs hover:bg-white hover:text-stone-900 transition-all shadow-xl">
            <span className="tracking-[0.3em]">아카이브 잠금 해제</span>
          </button>
        </div>
      )}
    </div>
  );
