import React, { useState, useEffect } from 'react';
import { Performance } from '../types';
import { getUpcomingPerformances } from '../services/geminiService';
import { Calendar, MapPin, User, ExternalLink, Loader2, Ticket, Search, Heart, Check, Music } from 'lucide-react';

interface PerformanceInfoProps {
  onSave: (p: Performance) => void;
  isSaved: (id: string) => boolean;
}

export const PerformanceInfo: React.FC<PerformanceInfoProps> = ({ onSave, isSaved }) => {
  const [performances, setPerformances] = useState<Performance[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [isSearching, setIsSearching] = useState(false);

  const fetchPerformances = async (query: string = "") => {
    if (query) setIsSearching(true);
    else setLoading(true);

    try {
      const today = new Date().toISOString().split('T')[0];
      const data = await getUpcomingPerformances(today, query);
      setPerformances(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
      setIsSearching(false);
    }
  };

  useEffect(() => {
    fetchPerformances();
  }, []);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    fetchPerformances(searchQuery);
  };

  return (
    <div className="max-w-5xl mx-auto space-y-20 animate-in fade-in duration-1000 pb-20">
      <div className="text-center space-y-4">
        <span className="text-[10px] font-black uppercase tracking-[0.5em] text-[#9A84A1]">공연 및 이벤트</span>
        <h2 className="text-4xl md:text-6xl font-logo font-black text-black uppercase tracking-tight leading-none">The Live Index</h2>
      </div>

      <div className="bg-[#9A84A1] p-12 shadow-premium">
        <form onSubmit={handleSearch} className="flex flex-col md:flex-row gap-6">
          <div className="relative flex-grow">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-white/40" />
            <input 
              type="text" 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="도시, 작곡가, 공연장 또는 아티스트 검색..." 
              className="w-full pl-16 pr-8 py-5 bg-white/10 border border-white/20 text-white focus:outline-none focus:border-white text-lg placeholder:text-white/30" 
            />
          </div>
          <button 
            type="submit"
            disabled={isSearching}
            className="px-12 py-5 bg-stone-900 text-white font-bold text-xs hover:bg-white hover:text-stone-900 transition shadow-2xl flex items-center justify-center space-x-4"
          >
            {isSearching ? <Loader2 className="w-5 h-5 animate-spin" /> : <Search className="w-5 h-5" />}
            <span className="tracking-[0.2em]">이벤트 검색</span>
          </button>
        </form>
      </div>

      {loading ? (
        <div className="flex flex-col items-center py-32 space-y-8">
          <Loader2 className="w-10 h-10 text-[#9A84A1] animate-spin" />
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-8">
          {performances.map((p) => (
            <div key={p.id} className="bg-[#F8F5FA] border border-stone-50 flex flex-col md:flex-row group hover:shadow-premium transition-all duration-700">
              <div className="md:w-52 h-52 md:h-auto bg-stone-900 flex items-center justify-center text-white relative overflow-hidden flex-shrink-0">
                <Music className="w-12 h-12 opacity-5" />
                <div className="absolute inset-0 flex items-center justify-center">
                   <div className="text-center">
                     <span className="block text-4xl font-logo font-black text-white mb-2">{p.date.split('-')[2] || '24'}</span>
                     <span className="block text-[8px] font-black uppercase tracking-widest opacity-30">공연 예정</span>
                   </div>
                </div>
              </div>
              <div className="p-12 flex flex-col justify-between flex-grow bg-white">
                <div className="space-y-6">
                  <h3 className="text-3xl font-bold text-stone-900 tracking-tight leading-tight uppercase">{p.title}</h3>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-8 text-[11px] font-bold text-stone-500 uppercase tracking-widest">
                    <span className="flex items-center"><MapPin className="w-4 h-4 mr-3 text-[#9A84A1]" /> {p.venue}</span>
                    <span className="flex items-center"><User className="w-4 h-4 mr-3 text-[#9A84A1]" /> {p.performer}</span>
                  </div>
                </div>
                <div className="mt-12 flex items-center justify-between border-t border-stone-50 pt-10">
                    <button 
                      onClick={() => onSave(p)}
                      className={`flex items-center space-x-3 px-6 py-3 transition text-[11px] font-bold tracking-tight
                        ${isSaved(p.id) ? 'text-stone-900 bg-[#F8F5FA]' : 'text-stone-300 hover:text-[#9A84A1]'}`}
                    >
                      {isSaved(p.id) ? <Check className="w-4 h-4" /> : <Heart className="w-4 h-4" />}
                      <span>{isSaved(p.id) ? '보관됨' : '공연 저장'}</span>
                    </button>
                    <a 
                      href={p.link} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="flex items-center space-x-4 px-10 py-5 bg-stone-900 text-white font-bold text-[10px] hover:bg-[#9A84A1] transition shadow-xl"
                    >
                      <span>티켓 예매하기</span>
                      <ExternalLink className="w-4 h-4" />
                    </a>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

