import React, { useState, useEffect } from 'react';
import { ClassicalPiece } from '../types';
import { getInspirations, CurationInspiration } from '../services/geminiService';
import { 
  Sparkles, Check, MessageCircle, Mail, Music, Search, 
  RefreshCw, Lightbulb, PenTool, ArrowUpRight, Asterisk, Loader2
} from 'lucide-react';

interface CuratorWorkplaceProps {
  candidates: ClassicalPiece[];
  onConfirm: (piece: ClassicalPiece) => void;
  onSearch: (composer: string, mood: string, discoveryMode: string, era: string, performer: string, occasion: string, instrumentation: string) => void;
  isSearching: boolean;
}

export const CuratorWorkplace: React.FC<CuratorWorkplaceProps> = ({ candidates, onConfirm, onSearch, isSearching }) => {
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [editedText, setEditedText] = useState("");
  const [copyFeedback, setCopyFeedback] = useState<string | null>(null);

  const [searchComposer, setSearchComposer] = useState("");
  const [searchMood, setSearchMood] = useState("");
  const [searchPerformer, setSearchPerformer] = useState("");
  const [searchOccasion, setSearchOccasion] = useState("");
  const [searchInstrumentation, setSearchInstrumentation] = useState("");
  const [discoveryMode, setDiscoveryMode] = useState("balanced");
  const [era, setEra] = useState("");

  const [inspirations, setInspirations] = useState<CurationInspiration[]>([]);
  const [loadingInspirations, setLoadingInspirations] = useState(false);

  useEffect(() => {
    loadInspirations();
  }, []);

  const loadInspirations = async () => {
    setLoadingInspirations(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const items = await getInspirations(today);
      setInspirations(items);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingInspirations(false);
    }
  };

  const handleApplyInspiration = (ins: CurationInspiration) => {
    setSearchComposer(ins.filters.composer || "");
    setSearchPerformer(ins.filters.performer || "");
    setSearchMood(ins.filters.mood || "");
    setSearchOccasion(ins.filters.occasion || "");
    setSearchInstrumentation(ins.filters.instrumentation || "");
    setDiscoveryMode(ins.filters.discoveryMode || "balanced");
    setEra(ins.filters.era || "");

    setSelectedIdx(null);
    onSearch(
      ins.filters.composer || "",
      ins.filters.mood || "",
      ins.filters.discoveryMode || "balanced",
      ins.filters.era || "",
      ins.filters.performer || "",
      ins.filters.occasion || "",
      ins.filters.instrumentation || ""
    );
  };

  const handleSelect = (i: number) => {
    setSelectedIdx(i);
    const p = candidates[i];
    // 이모지 없이 텍스트 정제
    setEditedText(`[Kyth Classical 오늘의 큐레이션]\n\n마스터피스: ${p.composer} - ${p.title}\n연주: ${p.performer}\n\n[곡의 이야기]\n${p.description}\n\n[마에스트로의 통찰]\n${p.funFact}\n\n감상하기: https://www.youtube.com/results?search_query=${encodeURIComponent(p.youtubeQuery)}`);

    setTimeout(() => {
      const editorSection = document.getElementById('manuscript-editor');
      if (editorSection) editorSection.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const handleFilterSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSelectedIdx(null);
    onSearch(searchComposer, searchMood, discoveryMode, era, searchPerformer, searchOccasion, searchInstrumentation);
  };

  const showFeedback = (msg: string) => {
    setCopyFeedback(msg);
    setTimeout(() => setCopyFeedback(null), 2000);
  };

  return (
    <div className="space-y-32 animate-in fade-in duration-1000 max-w-6xl mx-auto pb-20">

      {/* 1. Perspective Section */}
      <div className="space-y-12">
        <div className="flex flex-col md:flex-row justify-between items-end gap-10">
           <div className="space-y-4 text-left max-w-xl">
              <div className="flex items-center space-x-3">
                <Asterisk className="w-5 h-5 text-[#9A84A1]" />
                <span className="text-[10px] font-black uppercase tracking-[0.5em] text-stone-400">큐레이션 인스피레이션</span>
              </div>
              <h2 className="text-4xl md:text-6xl font-logo font-black text-black leading-tight">
                Perspective <br />
                <span className="serif-italic italic font-normal text-[#9A84A1]">of the Day.</span>
              </h2>
           </div>
           <button onClick={loadInspirations} className="group flex items-center space-x-4 px-8 py-4 bg-[#F8F5FA] border border-stone-100 transition-all hover:bg-stone-900 hover:text-white">
             <RefreshCw className={`w-4 h-4 text-stone-400 group-hover:text-white ${loadingInspirations ? 'animate-spin' : ''}`} />
             <span className="text-[11px] font-bold tracking-tight">아이디어 동기화</span>
           </button>
        </div>

        <section className="grid grid-cols-1 md:grid-cols-3 gap-1">
          {loadingInspirations ? (
            [1, 2, 3].map(i => <div key={i} className="h-64 bg-[#F8F5FA] animate-pulse" />)
          ) : (
            inspirations.map((ins, i) => (
              <div 
                key={i}
                onClick={() => handleApplyInspiration(ins)}
                className="group relative p-12 bg-[#F8F5FA] border border-stone-100 cursor-pointer hover:bg-stone-900 transition-all duration-300 overflow-hidden"
              >
                <div className="absolute top-0 right-0 p-8 opacity-0 group-hover:opacity-100 transition-opacity">
                  <ArrowUpRight className="w-5 h-5 text-[#9A84A1]" />
                </div>
                <h4 className="text-lg font-black text-stone-900 mb-4 group-hover:text-white transition-colors uppercase tracking-tight leading-tight">{ins.theme}</h4>
                <p className="text-[13px] text-stone-400 font-medium leading-relaxed mb-8 group-hover:text-stone-300 transition-colors">{ins.reason}</p>
                <div className="text-[10px] font-black uppercase tracking-widest text-[#9A84A1] flex items-center">
                   <span>즉시 큐레이션 실행</span>
                </div>
              </div>
            ))
          )}
        </section>
      </div>

      {/* 2. Curation Engine */}
      <section className="bg-[#F8F5FA] border-y-2 border-stone-900 py-20 relative group">
        <div className="max-w-5xl mx-auto px-6 space-y-16">
          <div className="flex items-center space-x-3">
             <div className="w-1.5 h-1.5 bg-[#9A84A1]"></div>
             <span className="text-[10px] font-black uppercase tracking-[0.5em] text-stone-400">마스터 엔진 컨트롤</span>
          </div>

          <form onSubmit={handleFilterSubmit} className="space-y-16 relative z-10">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12">
              {[
                { label: '상황 / 장면', value: searchOccasion, setter: setSearchOccasion, placeholder: '예: 비오는 오후' },
                { label: '악기 / 구성', value: searchInstrumentation, setter: setSearchInstrumentation, placeholder: '예: 첼로 솔로' },
                { label: '작곡가', value: searchComposer, setter: setSearchComposer, placeholder: '선택 사항' },
                { label: '연주자', value: searchPerformer, setter: setSearchPerformer, placeholder: '선택 사항' },
              ].map((f, idx) => (
                <div key={idx} className="space-y-4">
                  <label className="text-[10px] font-black uppercase text-stone-400 tracking-[0.2em]">{f.label}</label>
                  <div className="relative group">
                    <input 
                      type="text" 
                      value={f.value} 
                      onChange={(e) => f.setter(e.target.value)} 
                      placeholder={f.placeholder} 
                      className="w-full px-0 py-4 bg-transparent border-b border-stone-200 text-stone-900 focus:border-stone-900 transition-all outline-none font-light text-xl placeholder:text-stone-300" 
                    />
                    <div className="absolute bottom-0 left-0 w-0 h-[2px] bg-stone-900 group-focus-within:w-full transition-all duration-500"></div>
                  </div>
                </div>
              ))}
            </div>

            <button 
              type="submit" 
              disabled={isSearching} 
              className="w-full bg-stone-900 text-white py-8 font-black text-xs hover:bg-[#9A84A1] transition-all transform active:scale-[0.99] shadow-2xl disabled:opacity-50 flex items-center justify-center space-x-6 group"
            >
              {isSearching ? <Loader2 className="w-6 h-6 animate-spin" /> : <Sparkles className="w-6 h-6 group-hover:rotate-12 transition-transform" />}
              <span className="tracking-[0.4em]">{isSearching ? "명곡 데이터를 분석 중..." : "분석 및 탐색 시작"}</span>
            </button>
          </form>
        </div>
      </section>

      {/* 3. Candidates Selection */}
      <section className="space-y-16">
        <div className="flex items-center space-x-4 border-b border-stone-100 pb-8">
           <Music className="w-7 h-7 text-black" />
           <h2 className="text-3xl font-logo font-black text-black uppercase tracking-tight">발견된 후보군</h2>
        </div>

        {isSearching ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-1">
            {[1, 2, 3].map(i => <div key={i} className="bg-[#F8F5FA] h-80 border border-stone-100 animate-pulse" />)}
          </div>
        ) : candidates.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-1">
            {candidates.map((p, i) => (
              <div 
                key={p.id}
                onClick={() => handleSelect(i)}
                className={`cursor-pointer group relative p-12 border transition-all duration-500
                  ${selectedIdx === i 
                    ? 'bg-[#F8F5FA] border-stone-900 shadow-premium z-10' 
                    : 'bg-white border-stone-100 hover:bg-[#F8F5FA] hover:z-10 hover:shadow-xl hover:border-stone-400'}`}
              >
                <span className="text-[10px] font-black uppercase tracking-widest text-[#9A84A1] mb-4 block">{p.era}</span>
                <h4 className="text-2xl font-logo font-black text-stone-900 mb-4 leading-tight tracking-tight uppercase">{p.title}</h4>
                <p className="text-[13px] font-bold text-stone-400 uppercase tracking-widest mb-12">{p.composer}</p>
                <div className={`flex items-center text-[10px] font-black uppercase tracking-widest transition-colors
                   ${selectedIdx === i ? 'text-stone-900' : 'text-stone-200 group-hover:text-stone-900'}`}>
                   {selectedIdx === i ? <Check className="w-4 h-4 mr-3 text-[#9A84A1]" /> : <PenTool className="w-4 h-4 mr-3" />}
                   <span>{selectedIdx === i ? '편집 준비 완료' : '상세 내용 검토'}</span>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="py-24 text-center border-2 border-dashed border-stone-100 bg-[#F8F5FA]">
             <p className="text-stone-400 font-logo italic text-xl">엔진을 가동하여 오늘의 곡 후보를 발견하세요.</p>
          </div>
        )}
      </section>

      {/* 4. Manuscript Editor */}
      {selectedIdx !== null && (
        <section id="manuscript-editor" className="bg-[#F8F5FA] border border-stone-900 shadow-premium overflow-hidden animate-in slide-in-from-bottom-20 duration-1000">
          <div className="p-12 md:p-24 grid grid-cols-1 lg:grid-cols-2 gap-24">
            <div className="space-y-8">
              <div className="flex items-center justify-between">
                 <label className="text-[10px] font-black uppercase tracking-[0.5em] text-[#9A84A1]">에디토리얼 편집기</label>
                 <span className="text-[9px] font-bold text-stone-300 uppercase tracking-widest">실시간 아카이브 동기화</span>
              </div>
              <textarea 
                value={editedText} 
                onChange={(e) => setEditedText(e.target.value)} 
                className="w-full h-[550px] p-12 bg-white border-none text-stone-900 leading-[1.8] focus:outline-none transition-all text-lg font-light shadow-inner-soft resize-none" 
              />
            </div>

            <div className="flex flex-col justify-center space-y-16">
              <div className="space-y-8">
                <h4 className="text-[10px] font-black uppercase tracking-[0.5em] text-[#9A84A1]">배포 프로토콜</h4>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                  <button onClick={() => { navigator.clipboard.writeText(editedText); showFeedback("복사되었습니다."); }} className="flex flex-col items-center justify-center space-y-6 p-12 bg-white hover:bg-stone-900 text-stone-900 hover:text-white border border-stone-100 hover:border-stone-900 transition-all transform hover:-translate-y-1 group">
                    <div className="w-14 h-14 bg-stone-50 flex items-center justify-center group-hover:bg-[#9A84A1] transition-all">
                      <MessageCircle className="w-6 h-6" />
                    </div>
                    <span className="text-[11px] font-bold tracking-widest">채널 브로드캐스트</span>
                  </button>
                  <button onClick={() => { navigator.clipboard.writeText(editedText); showFeedback("복사되었습니다."); }} className="flex flex-col items-center justify-center space-y-6 p-12 bg-white hover:bg-stone-900 text-stone-900 hover:text-white border border-stone-100 hover:border-stone-900 transition-all transform hover:-translate-y-1 group">
                    <div className="w-14 h-14 bg-stone-50 flex items-center justify-center group-hover:bg-[#9A84A1] transition-all">
                      <Mail className="w-6 h-6" />
                    </div>
                    <span className="text-[11px] font-bold tracking-widest">저널 뉴스레터</span>
                  </button>
                </div>
              </div>

              <div className="space-y-6 pt-10 border-t border-stone-200">
                 <button 
                   onClick={() => onConfirm(candidates[selectedIdx])} 
                   className="w-full py-9 bg-stone-900 text-white font-black text-xs hover:bg-[#9A84A1] transition-all shadow-2xl active:scale-95"
                 >
                   <span className="tracking-[0.4em]">오늘의 명곡으로 확정하기</span>
                 </button>
                 <p className="text-center text-[9px] font-bold text-stone-400 uppercase tracking-widest">발행 시 이 곡은 오늘 하루 전체 서비스의 메인으로 노출됩니다.</p>
              </div>
            </div>
          </div>

          {copyFeedback && (
            <div className="fixed bottom-10 left-1/2 -translate-x-1/2 glass px-10 py-4 font-bold text-[#9A84A1] shadow-2xl animate-in fade-in slide-in-from-bottom-4 z-50">
              {copyFeedback}
            </div>
          )}
        </section>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { ClassicalPiece, SubscriptionTier } from '../types';
import { Share2, Youtube, Quote, Info, Check, Copy, Lock, Sparkles, Crown, User, Heart, Play, Music } from 'lucide-react';

interface RecommendationCardProps {
  piece: ClassicalPiece;
  tier: SubscriptionTier;
  onUpgrade: () => void;
  onSave: (p: ClassicalPiece) => void;
  isSaved: (id: string) => boolean;
}

export const RecommendationCard: React.FC<RecommendationCardProps> = ({ piece, tier, onUpgrade, onSave, isSaved }) => {
  const [copied, setCopied] = useState(false);
  const isPremium = tier === SubscriptionTier.PREMIUM;

  const handleShare = async () => {
    const shareText = `[Kyth Classical] ${piece.composer} - ${piece.title}\n감상: https://www.youtube.com/results?search_query=${encodeURIComponent(piece.youtubeQuery)}`;
    if (navigator.share) {
      try { await navigator.share({ title: 'Kyth Classical', text: shareText, url: window.location.href }); } catch (err) {}
    } else {
      navigator.clipboard.writeText(shareText);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="animate-in fade-in slide-in-from-bottom-8 duration-1000 max-w-6xl mx-auto px-4 pb-20">
      <div className="bg-[#F8F5FA] shadow-premium overflow-hidden border border-stone-100 flex flex-col lg:flex-row">

        {/* Cover Section */}
        <div className="lg:w-2/5 relative bg-[#1A1A1A] p-12 flex flex-col justify-between overflow-hidden min-h-[550px]">
          <div className="absolute top-0 left-0 w-full h-full pointer-events-none overflow-hidden">
            <div className="absolute -top-24 -right-24 w-96 h-96 border border-white/5" />
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[150%] h-[1px] bg-white/5 rotate-45" />
          </div>

          <div className="relative z-10 flex justify-between items-start">
             <div className="flex flex-col">
               <span className="text-[10px] font-black uppercase tracking-[0.5em] text-[#9A84A1] mb-2">오늘의 선정</span>
               <div className="h-1 w-12 bg-[#9A84A1]"></div>
             </div>
             <button 
                onClick={() => onSave(piece)}
                className={`p-4 transition-all duration-500 transform hover:scale-110 active:scale-90 shadow-2xl
                  ${isSaved(piece.id) ? 'bg-[#9A84A1] text-white' : 'bg-white/5 text-white/40 hover:text-white border border-white/10 hover:bg-white/10'}`}
              >
                <Heart className={`w-6 h-6 ${isSaved(piece.id) ? 'fill-current' : ''}`} />
              </button>
          </div>

          <div className="relative z-10 space-y-6">
             <h2 className="text-5xl md:text-7xl font-logo font-black text-white leading-[0.85] tracking-tight">
               {piece.title}
             </h2>
             <div className="flex items-center space-x-6">
               <div className="h-px w-10 bg-[#9A84A1]"></div>
               <p className="text-2xl font-logo serif-italic italic text-[#9A84A1] lowercase">
                 composed by {piece.composer}
               </p>
             </div>
          </div>

          <div className="relative z-10 flex justify-between items-end border-t border-white/5 pt-12">
             <div className="flex flex-col">
                <span className="text-[8px] font-black uppercase tracking-widest text-white/30 mb-1">음악 사조</span>
                <span className="text-xs font-bold text-white uppercase tracking-widest">{piece.era}</span>
             </div>
             <div className="flex flex-col text-right">
                <span className="text-[8px] font-black uppercase tracking-widest text-white/30 mb-1">작곡 연도</span>
                <span className="text-xs font-bold text-white uppercase tracking-widest">{piece.year}</span>
             </div>
          </div>
        </div>

        {/* Content Section */}
        <div className="lg:w-3/5 p-12 md:p-20 space-y-20 bg-white">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-10 border-b border-stone-50 pb-12">
            <div className="flex items-center space-x-8">
              <div className="w-16 h-16 bg-[#F8F5FA] border border-stone-50 flex items-center justify-center text-[#9A84A1]">
                <User className="w-6 h-6" />
              </div>
              <div className="space-y-1">
                <p className="text-[9px] font-black text-stone-300 uppercase tracking-widest">추천 명연주</p>
                <h4 className="text-3xl font-bold text-stone-900 tracking-tight">{piece.performer}</h4>
              </div>
            </div>
          </div>

          <div className="space-y-10">
            <div className="flex items-center space-x-4">
              <span className="text-[10px] font-black text-stone-900 uppercase tracking-[0.5em]">전문 큐레이터의 분석</span>
              <div className="h-px flex-grow bg-stone-100"></div>
            </div>
            <p className="text-lg md:text-2xl text-stone-800 leading-relaxed font-light">
              {piece.description}
            </p>
          </div>

          <div className="relative">
            {!isPremium && (
              <div className="absolute inset-0 flex flex-col items-center justify-center p-12 text-center bg-[#F8F5FA]/80 backdrop-blur-sm z-20">
                <Lock className="w-8 h-8 text-[#9A84A1] mb-6" />
                <h4 className="text-3xl font-logo font-black text-stone-900 mb-3 uppercase">Premium Logic</h4>
                <p className="text-stone-500 text-sm max-w-sm mb-12 font-medium">거장의 비화와 심층 해설은 프리미엄 멤버십에게만 공개됩니다.</p>
                <button onClick={onUpgrade} className="px-14 py-6 bg-stone-900 text-white font-bold text-[11px] hover:bg-[#9A84A1] transition-all shadow-2xl">
                  프리미엄 업그레이드
                </button>
              </div>
            )}

            <div className="bg-[#F8F5FA] p-14 border border-stone-50 relative group">
              <div className="flex items-center space-x-3 mb-10 relative z-10">
                <Sparkles className="w-5 h-5 text-[#9A84A1]" />
                <h3 className="text-[10px] font-black text-stone-400 uppercase tracking-widest">마에스트로의 통찰</h3>
              </div>
              <p className={`text-stone-900 leading-relaxed text-xl serif-italic italic relative z-10 ${!isPremium ? 'blur-lg select-none opacity-20' : ''}`}>
                "{piece.funFact}"
              </p>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row justify-between items-center gap-12 pt-12">
            <div className="flex flex-wrap gap-3">
              {piece.mood.split(',').map((m, i) => (
                <span key={i} className="px-5 py-2 bg-stone-900/5 text-stone-500 text-[10px] font-bold uppercase tracking-wider">
                  {m.trim()}
                </span>
              ))}
            </div>

            <div className="flex items-center space-x-6">
              <button onClick={handleShare} className="p-6 border border-stone-100 text-stone-400 hover:text-stone-900 transition-all">
                {copied ? <Check className="w-6 h-6 text-[#9A84A1]" /> : <Share2 className="w-6 h-6" />}
              </button>
              <a 
                href={`https://www.youtube.com/results?search_query=${encodeURIComponent(piece.youtubeQuery)}`} 
                target="_blank" rel="noopener noreferrer" 
                className="flex items-center space-x-6 px-14 py-6 bg-stone-900 text-white transition-all shadow-2xl hover:bg-[#9A84A1] hover:-translate-y-1 group"
              >
                <Play className="w-5 h-5 fill-current" />
                <span className="font-bold tracking-[0.2em] text-[11px]">지금 감상하기</span>
              </a>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};
